import express from 'express';
import cors from 'cors';
import { GoogleGenAI, Modality, Type } from "@google/genai";
import dotenv from 'dotenv';

dotenv.config();

const app = express();
const port = process.env.PORT || 8080;

// Enable CORS and JSON body parsing (large limit for images)
app.use(cors());
app.use(express.json({ limit: '50mb' }));

// Initialize Gemini Client
const apiKey = process.env.API_KEY;
if (!apiKey) {
    console.warn("WARNING: API_KEY is not set in environment variables.");
}
const ai = new GoogleGenAI({ apiKey: apiKey || '' });

// Helper function for System Instructions (Moved from frontend)
function createSystemInstruction(shop: any): string {
  return `
Eres **${shop.aiName}**, el Asistente de Estilismo AI de **${shop.name}**.

Tu personalidad es la de un **barbero profesional, experto y amigable**, con el siguiente carácter específico: ${shop.aiPersona}
Tu misión es ayudar a los clientes a encontrar su estilo perfecto y responder preguntas generales sobre estilismo.

---

## 🧠 Tu comportamiento y reglas

1.  **Rol Principal:** Eres un barbero experto que da recomendaciones de estilo y responde preguntas sobre cortes de cabello, cuidado del cabello y tendencias. **No tienes información sobre ${shop.name} (horarios, precios, ubicación).**
2.  **Análisis de Fotos (IMPORTANTE):**
    *   Cuando se te pida analizar fotos de un cliente, tu única tarea es responder con un objeto JSON.
    *   Este JSON debe contener un campo \`analysis\` (un texto amigable explicando tu recomendación basada en la forma del rostro, tipo de cabello, etc.) y un campo \`styles\` (un array con exactamente 4 nombres de cortes de cabello).
    *   **NO** incluyas texto adicional fuera del JSON. Tu respuesta debe ser **solo el JSON**.
3.  **Chat General:** Para todas las demás preguntas, responde de forma conversacional y útil sobre estilismo.
4.  **Agendar Cita o Información Específica:** Si te preguntan sobre citas, precios, o detalles de la barbería, responde amablemente: "Para agendar una cita o consultar precios en ${shop.name}, por favor contacta directamente con ellos. ¡Estarán encantados de atenderte!".
5.  Mantén el tono positivo, profesional y motivador, siempre acorde a tu personalidad asignada.
`;
}

// --- Endpoints ---

// 1. Chat Endpoint
app.post('/api/chat', async (req, res) => {
    try {
        const { message, history, shop } = req.body;

        // Construct chat history for the model
        const contents = history.map((msg: any) => ({
            role: msg.role,
            parts: [{ text: msg.parts[0].text }]
        }));

        // Add the new user message
        contents.push({ role: 'user', parts: [{ text: message }] });

        const model = ai.models.generateContent({
            model: 'gemini-2.5-flash',
            config: {
                systemInstruction: createSystemInstruction(shop),
                temperature: 0.7,
            },
            contents: contents
        });

        const response = await model;
        res.json({ text: response.text });
    } catch (error: any) {
        console.error('Error in /api/chat:', error);
        res.status(500).json({ error: error.message || 'Internal Server Error' });
    }
});

// 2. Style Analysis Endpoint
app.post('/api/analyze', async (req, res) => {
    try {
        const { frontImage, sideImage, shop } = req.body;

        const responseSchema = {
            type: Type.OBJECT,
            properties: {
                styles: {
                    type: Type.ARRAY,
                    description: 'Una lista de exactamente 4 nombres de estilos de corte de cabello recomendados.',
                    items: { type: Type.STRING }
                },
                finalRecommendation: {
                    type: Type.STRING,
                    description: 'Una recomendación final y concluyente.'
                }
            },
            required: ['styles', 'finalRecommendation']
        };

        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: {
                parts: [
                    { inlineData: { mimeType: frontImage.mimeType, data: frontImage.data } },
                    { inlineData: { mimeType: sideImage.mimeType, data: sideImage.data } },
                    { text: "Analiza estas dos fotos (frente y perfil) de un cliente. Recomienda 4 estilos y una recomendación final. Responde solo con JSON." }
                ]
            },
            config: {
                systemInstruction: createSystemInstruction(shop),
                responseMimeType: "application/json",
                responseSchema: responseSchema,
                temperature: 0.5,
            },
        });

        res.json(JSON.parse(response.text || '{}'));
    } catch (error: any) {
        console.error('Error in /api/analyze:', error);
        res.status(500).json({ error: error.message });
    }
});

// 3. Image Generation Endpoint
app.post('/api/generate-image', async (req, res) => {
    try {
        const { image, style, angle, lighting, type, color } = req.body; // type: 'style', 'color', 'highlights'

        let prompt = "";
        const imagePart = { inlineData: { data: image.data, mimeType: image.mimeType } };

        if (type === 'style') {
            const angleInstruction = {
                'Frente': 'desde un ángulo frontal (front view)',
                'Perfil': 'desde un ángulo de perfil (side view)',
                'Tres Cuartos': 'desde un ángulo de tres cuartos (three-quarter view)',
            }[angle as string] || 'frontal';

            const lightingInstruction = lighting !== 'Natural' ? `La iluminación debe ser '${lighting}'.` : '';
            prompt = `Aplica el siguiente peinado a la persona en la foto: '${style}'. La vista debe ser ${angleInstruction}. ${lightingInstruction} El resultado debe ser fotorrealista, cambiando solo el cabello.`;

        } else if (type === 'color') {
            prompt = `Cambia el color del cabello de la persona en la foto a ${color}. El resultado debe ser fotorrealista, manteniendo el peinado y los rasgos faciales.`;
        } else if (type === 'highlights') {
            prompt = `Añade mechas de color '${color}' al cabello en la foto. El resultado debe ser fotorrealista, manteniendo el peinado y el color base.`;
        }

        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: { parts: [imagePart, { text: prompt }] },
            config: {
                responseModalities: [Modality.IMAGE],
            },
        });

        const firstCandidate = response?.candidates?.[0];
        let generatedImageBase64 = null;

        if (firstCandidate?.content?.parts) {
            for (const part of firstCandidate.content.parts) {
                if (part.inlineData) {
                    generatedImageBase64 = `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
                    break;
                }
            }
        }

        if (!generatedImageBase64) {
            throw new Error("No image generated");
        }

        res.json({ image: generatedImageBase64 });

    } catch (error: any) {
        console.error('Error in /api/generate-image:', error);
        res.status(500).json({ error: error.message });
    }
});

// 4. Slots Endpoint
app.post('/api/slots', async (req, res) => {
    try {
        const { date, service, shop } = req.body;

        const slotsSchema = {
            type: Type.OBJECT,
            properties: {
                slots: {
                    type: Type.ARRAY,
                    items: { type: Type.STRING }
                }
            },
            required: ['slots']
        };

        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: `Eres el sistema de reservas para "${shop.name}". Genera horarios disponibles para "${service}" el "${date}". Devuelve JSON con clave "slots".`,
            config: {
                responseMimeType: "application/json",
                responseSchema: slotsSchema,
                temperature: 1,
            },
        });

        res.json(JSON.parse(response.text || '{}'));
    } catch (error: any) {
        console.error('Error in /api/slots:', error);
        res.status(500).json({ error: error.message });
    }
});

app.listen(port, () => {
    console.log(`Server running on port ${port}`);
});

import { BarberShop } from "../types";

// In production, this would be the URL of your Cloud Run instance.
// For local development, it might be http://localhost:8080 or a proxy.
// We assume a relative path /api assuming the frontend is served by the same origin 
// or a proxy is configured in development.
const API_BASE_URL = '/api'; 

// --- Types for Client Side usage ---

export interface ChatSession {
    sendMessageStream: (params: { message: string }) => Promise<AsyncGenerator<{ text: string }>>;
    history: { role: 'user' | 'model', parts: { text: string }[] }[];
}

export function initChatSession(shop: BarberShop): ChatSession {
  // Create a session object that maintains history locally and calls the server
  const history: { role: 'user' | 'model', parts: { text: string }[] }[] = [];

  return {
    history,
    sendMessageStream: async ({ message }) => {
        try {
            const response = await fetch(`${API_BASE_URL}/chat`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ 
                    message, 
                    history: history, // Send history context
                    shop 
                })
            });

            if (!response.ok) throw new Error('Network response was not ok');
            const data = await response.json();

            // Update local history
            history.push({ role: 'user', parts: [{ text: message }] });
            history.push({ role: 'model', parts: [{ text: data.text }] });

            // Simulate stream for frontend compatibility
            async function* streamGenerator() {
                // Yield the whole text at once, or simulate chunks if needed for UI effect
                // For now, simple yield is fine
                yield { text: data.text };
            }

            return streamGenerator();

        } catch (error) {
            console.error("Chat API Error:", error);
            throw error;
        }
    }
  };
}

export async function getStyleRecommendations(frontImage: any, sideImage: any, shop: BarberShop): Promise<{ styles: string[], finalRecommendation: string }> {
  // Extract base64 data from the Part objects passed by frontend
  const frontPayload = { mimeType: frontImage.inlineData.mimeType, data: frontImage.inlineData.data };
  const sidePayload = { mimeType: sideImage.inlineData.mimeType, data: sideImage.inlineData.data };

  const response = await fetch(`${API_BASE_URL}/analyze`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ frontImage: frontPayload, sideImage: sidePayload, shop })
  });

  if (!response.ok) throw new Error('Analysis API Failed');
  return await response.json();
}


export async function generateStyledImage(base64ImageData: string, mimeType: string, style: string, angle: string, lighting: string): Promise<string> {
  const response = await fetch(`${API_BASE_URL}/generate-image`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
          image: { data: base64ImageData, mimeType },
          type: 'style',
          style,
          angle,
          lighting
      })
  });

  if (!response.ok) throw new Error('Image Gen API Failed');
  const result = await response.json();
  return result.image;
}

export async function applyHairColor(base64ImageData: string, mimeType: string, color: string): Promise<string> {
    const response = await fetch(`${API_BASE_URL}/generate-image`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
            image: { data: base64ImageData, mimeType },
            type: 'color',
            color
        })
    });

    if (!response.ok) throw new Error('Color API Failed');
    const result = await response.json();
    return result.image;
}

export async function applyHairHighlights(base64ImageData: string, mimeType: string, color: string): Promise<string> {
    const response = await fetch(`${API_BASE_URL}/generate-image`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
            image: { data: base64ImageData, mimeType },
            type: 'highlights',
            color
        })
    });

    if (!response.ok) throw new Error('Highlights API Failed');
    const result = await response.json();
    return result.image;
}

export async function getAvailableSlots(date: string, service: string, shop: BarberShop): Promise<string[]> {
    const response = await fetch(`${API_BASE_URL}/slots`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ date, service, shop })
    });

    if (!response.ok) throw new Error('Slots API Failed');
    const result = await response.json();
    return result.slots;
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
// Removed: import { Chat, Part } from '@google/genai'; -> We don't import from SDK directly anymore
import { auth } from './firebaseConfig'; 
import { Message, BarberShop, Booking, PaymentMethod, User } from './types';
import { barbershops } from './barbershops';
import { initChatSession, getStyleRecommendations, generateStyledImage, applyHairColor, applyHairHighlights, ChatSession } from './services/geminiService';
import { subscribeToUserBookings, subscribeToShopBookings, logoutUser } from './services/firebaseService';
import ImageModal from './components/ImageModal';
import Sidebar from './components/Sidebar';
import MainHeader from './components/MainHeader';
import ChatView from './views/ChatView';
import MirrorView from './views/MirrorView';
import BookingView from './views/BookingView';
import BookingsListView from './views/BookingsListView';
import ShopProfileView from './views/ShopProfileView';
import BillingView from './views/BillingView';
import AdminView from './views/AdminView';
import HomeView from './views/HomeView';
import LoginView from './views/LoginView';
import PlatformAdminView from './views/PlatformAdminView';

// Helper to convert File to Base64 Data URL
const fileToDataUrl = (file: File): Promise<{ dataUrl: string; data: string; mimeType: string }> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = () => {
            const dataUrl = reader.result as string;
            const data = dataUrl.split(',')[1];
            resolve({ dataUrl, data, mimeType: file.type });
        };
        reader.onerror = reject;
        reader.readAsDataURL(file);
    });
};

// Helper to convert Base64 Data URL back to a File object for sharing
const dataUrlToFile = async (dataUrl: string, fileName: string): Promise<File> => {
    const res = await fetch(dataUrl);
    const blob = await res.blob();
    return new File([blob], fileName, { type: blob.type });
};

type ActiveView = 'chat' | 'mirror' | 'booking' | 'bookingsList' | 'shopProfile' | 'billing' | 'admin' | 'platformAdmin';
type Screen = 'home' | 'login' | 'app';

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [isAiLoading, setIsAiLoading] = useState<boolean>(false);
  const [shops, setShops] = useState<BarberShop[]>(barbershops);
  const [activeView, setActiveView] = useState<ActiveView>('admin');
  const [bookings, setBookings] = useState<Booking[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const [screen, setScreen] = useState<Screen>('home');
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  // Firebase User state
  const [firebaseUser, setFirebaseUser] = useState<any | null>(null);

  const [appState, setAppState] = useState<'initial' | 'processing' | 'results'>('initial');
  const [frontUserImage, setFrontUserImage] = useState<{ data: string; mimeType: string, url: string } | null>(null);
  const [sideUserImage, setSideUserImage] = useState<{ data: string; mimeType: string, url: string } | null>(null);
  const [suggestedStyles, setSuggestedStyles] = useState<string[]>([]);
  const [analysisResult, setAnalysisResult] = useState<string | null>(null);

  // 12 slots: 0-3 Front, 4-7 Side, 8-11 ThreeQuarter
  const [originalGeneratedImages, setOriginalGeneratedImages] = useState<(string | null)[]>(Array(12).fill(null));
  const [generatedImages, setGeneratedImages] = useState<(string | null)[]>(Array(12).fill(null));
  const [isGeneratingImages, setIsGeneratingImages] = useState<boolean[]>(Array(12).fill(false));

  const [activeAngle, setActiveAngle] = useState<'front' | 'side' | 'threeQuarter'>('front');
  const [activeLighting, setActiveLighting] = useState<string>('Natural');

  const [modalImage, setModalImage] = useState<{ url: string; caption: string } | null>(null);

  const currentShop = shops.find(s => s.id === currentUser?.shopId) || shops[0]; // Fallback to first shop if mismatch
  // Changed Ref type to generic ChatSession interface from service
  const chatSession = useRef<ChatSession | null>(null);

  // --- Auth State Listener (Mock Mode Only) ---
  useEffect(() => {
    const storedRole = localStorage.getItem('userRole') as 'platformAdmin' | 'shopOwner';

    // Mock Mode: Check local storage for persistence
    const mockUserStr = localStorage.getItem('mockUser');
    if (storedRole && mockUserStr) {
        try {
            const user = JSON.parse(mockUserStr);
            const mappedUser: User = {
                id: user.uid,
                name: user.displayName || user.email || 'Usuario Demo',
                role: storedRole,
                avatarUrl: user.photoURL || 'https://via.placeholder.com/150',
                shopId: storedRole === 'shopOwner' ? '1' : undefined
            };
            setFirebaseUser(user);
            setCurrentUser(mappedUser);
            setScreen('app');
        } catch (e) {
            console.error("Failed to parse mock user", e);
        }
    }
  }, []);

  // --- Realtime Bookings Listener ---
  useEffect(() => {
      // Logic applies to both Real (via db) and Mock (via mock db) because service abstracts it
      if (currentUser && firebaseUser) {
          let unsubscribe: () => void;

          if (currentUser.role === 'shopOwner' && currentShop) {
              // If owner, listen to all bookings for their shop
              unsubscribe = subscribeToShopBookings(currentShop.name, (fetchedBookings) => {
                  setBookings(fetchedBookings);
              });
          } else {
              // If user/admin/other, listen to their own bookings
              unsubscribe = subscribeToUserBookings(firebaseUser.uid, (fetchedBookings) => {
                  setBookings(fetchedBookings);
              });
          }

          return () => {
              if (unsubscribe) unsubscribe();
          };
      }
  }, [currentUser, firebaseUser, currentShop]);


  const handleShowLogin = () => setScreen('login');

  const handleLogin = (user: any, role: 'platformAdmin' | 'shopOwner') => {
    localStorage.setItem('userRole', role);

    // If Mock Mode (auth is null), manually set state since listener won't fire
    if (!auth) {
        localStorage.setItem('mockUser', JSON.stringify(user));
        const mappedUser: User = {
            id: user.uid,
            name: user.displayName || user.email || 'Usuario Demo',
            role: role,
            avatarUrl: user.photoURL || 'https://via.placeholder.com/150',
            shopId: role === 'shopOwner' ? '1' : undefined
        };
        setCurrentUser(mappedUser);
        setFirebaseUser(user);
        setScreen('app');
    }

    setActiveView(role === 'platformAdmin' ? 'platformAdmin' : 'mirror');
  };

  const handleLogout = async () => {
    await logoutUser();
    localStorage.removeItem('userRole');
    localStorage.removeItem('mockUser');

    // If Mock Mode, manually clear state
    if (!auth) {
        setCurrentUser(null);
        setFirebaseUser(null);
        setScreen('home');
    }
  };

  const handleGoHome = () => {
    setScreen('home');
  };

  const handleAddBooking = (bookingDetails: Omit<Booking, 'id'>) => {
      // Listener handles updates
  };

  const handleUploadNew = () => {
      setAppState('initial');
      setFrontUserImage(null);
      setSideUserImage(null);
      setSuggestedStyles([]);
      setAnalysisResult(null);
      setGeneratedImages(Array(12).fill(null));
      setOriginalGeneratedImages(Array(12).fill(null));
      setIsGeneratingImages(Array(12).fill(false));
      setActiveAngle('front');
      setActiveLighting('Natural');
  };

  const initializeAndReset = useCallback((shop: BarberShop) => {
    handleUploadNew();
    try {
      chatSession.current = initChatSession(shop);
      setMessages([
        {
          id: 'init',
          sender: 'ai',
          text: shop.welcomeMessage,
        },
      ]);
    } catch (error) {
      console.error("Failed to initialize chat session:", error);
      setMessages([{
        id: 'error-init',
        sender: 'ai',
        text: 'Lo siento, no puedo conectarme en este momento. Asegúrate de que el servidor Backend esté funcionando.',
      }]);
    }
  }, []);

  useEffect(() => {
    if (currentShop) {
      initializeAndReset(currentShop);
    } else {
      setMessages([]);
      chatSession.current = null;
    }
  }, [currentShop, initializeAndReset]);

  const handlePhotosReady = async (frontFile: File, sideFile: File) => {
    if (!currentShop) return;
    setAppState('processing');
    setIsAiLoading(true);

    const [frontImg, sideImg] = await Promise.all([
        fileToDataUrl(frontFile),
        fileToDataUrl(sideFile)
    ]);

    setFrontUserImage({data: frontImg.data, mimeType: frontImg.mimeType, url: frontImg.dataUrl});
    setSideUserImage({data: sideImg.data, mimeType: sideImg.mimeType, url: sideImg.dataUrl});

    // Create Part-like structure expected by our new service adapter
    const frontImagePart = { inlineData: { mimeType: frontImg.mimeType, data: frontImg.data } };
    const sideImagePart = { inlineData: { mimeType: sideImg.mimeType, data: sideImg.data } };

    try {
        const { styles, finalRecommendation } = await getStyleRecommendations(frontImagePart, sideImagePart, currentShop);

        setAnalysisResult(finalRecommendation);
        setSuggestedStyles(styles);
        setAppState('results');
        setActiveView('mirror'); // Switch to mirror view to show results
        visualizeStyles(
            styles,
            { data: frontImg.data, mimeType: frontImg.mimeType },
            { data: sideImg.data, mimeType: sideImg.mimeType },
            'Natural'
        );

    } catch (error) {
      console.error('Error getting style recommendations:', error);
      setMessages((prev) => [...prev, {
        id: 'error-style-rec',
        sender: 'ai',
        text: '¡Vaya! Algo salió mal al analizar tus fotos. Por favor, asegúrate de que las imágenes sean nítidas y vuelve a intentarlo.',
      }]);
      handleUploadNew();
      setActiveView('chat');
    } finally {
      setIsAiLoading(false);
    }
  };

  const visualizeStyles = (
    styles: string[],
    frontImage: { data: string; mimeType: string },
    sideImage: { data: string; mimeType: string },
    lighting: string
    ) => {
    if (styles.length < 4) {
        console.warn("Not enough styles provided to visualize, padding with generic.");
        while(styles.length < 4) styles.push("Estilo por IA");
    }

    const imagesToGenerate: { image: any, style: string, angle: 'Frente' | 'Perfil' | 'Tres Cuartos', index: number }[] = [];

    // Indices: 0-3 Front, 4-7 Side
    styles.forEach((style, i) => {
        // Front View
        imagesToGenerate.push({
            image: frontImage,
            style: style,
            angle: 'Frente',
            index: i
        });
        // Side View
        imagesToGenerate.push({
            image: sideImage,
            style: style,
            angle: 'Perfil',
            index: i + 4
        });
    });


    // Sequential generation with slight delay to avoid rate limits/UI freeze
    const generateSequentially = async () => {
        for (const { image, style, angle, index } of imagesToGenerate) {
             setIsGeneratingImages(prev => { const next = [...prev]; next[index] = true; return next; });
             try {
                 // Add a small delay between requests
                 await new Promise(r => setTimeout(r, 400));
                 const generatedImageUrl = await generateStyledImage(image.data, image.mimeType, style, angle, lighting);
                 setGeneratedImages(prev => { const next = [...prev]; next[index] = generatedImageUrl; return next; });
                 setOriginalGeneratedImages(prev => { const next = [...prev]; next[index] = generatedImageUrl; return next; });
             } catch (error) {
                 console.error(`Error generating image for style "${style}" (index ${index}):`, error);
             } finally {
                 setIsGeneratingImages(prev => { const next = [...prev]; next[index] = false; return next; });
             }
        }
    };

    generateSequentially();
  };

  const handleRegenerateSingleImage = async (index: number) => {
    if (isGeneratingImages[index] || !suggestedStyles.length) return;

    // Determine config based on index
    // 0-3: Front
    // 4-7: Side
    // 8-11: Three Quarter
    let angle: 'Frente' | 'Perfil' | 'Tres Cuartos' = 'Frente';
    let sourceImage = frontUserImage;
    const styleIndex = index % 4;
    const style = suggestedStyles[styleIndex];

    if (index >= 4 && index < 8) {
        angle = 'Perfil';
        sourceImage = sideUserImage;
    } else if (index >= 8) {
        angle = 'Tres Cuartos';
        sourceImage = frontUserImage; 
    }

    if (!sourceImage) return;

    setIsGeneratingImages(prev => { const next = [...prev]; next[index] = true; return next; });
    try {
        const generatedImageUrl = await generateStyledImage(sourceImage.data, sourceImage.mimeType, style, angle, activeLighting);

        // Update both current view and original storage to keep consistency
        setGeneratedImages(prev => { const next = [...prev]; next[index] = generatedImageUrl; return next; });
        setOriginalGeneratedImages(prev => { const next = [...prev]; next[index] = generatedImageUrl; return next; });
    } catch (error) {
        console.error(`Error regenerating image at index ${index}:`, error);
    } finally {
        setIsGeneratingImages(prev => { const next = [...prev]; next[index] = false; return next; });
    }
  };

  const handleAngleChange = (angle: 'front' | 'side' | 'threeQuarter') => {
      setActiveAngle(angle);

      // If switching to Three Quarter and images not generated, generate them (indices 8-11)
      const startIdx = 8;
      const endIdx = 11;
      const needsGeneration = suggestedStyles.some((_, i) => !originalGeneratedImages[startIdx + i] && !isGeneratingImages[startIdx + i]);

      if (angle === 'threeQuarter' && needsGeneration && frontUserImage && sideUserImage) {
          const styles = suggestedStyles;
          const imagesToGenerate: { image: any, style: string, angle: 'Tres Cuartos', index: number }[] = [];

          styles.forEach((style, i) => {
             imagesToGenerate.push({
                 image: frontUserImage, // Using front image as base for 3Q estimation
                 style: style,
                 angle: 'Tres Cuartos',
                 index: startIdx + i
             });
          });

          const generateSequentially = async () => {
             for(const { image, style, angle, index } of imagesToGenerate) {
                  setIsGeneratingImages(prev => { const next = [...prev]; next[index] = true; return next; });
                  try {
                      await new Promise(r => setTimeout(r, 300));
                      const generatedImageUrl = await generateStyledImage(image.data, image.mimeType, style, angle, activeLighting);
                      setGeneratedImages(prev => { const next = [...prev]; next[index] = generatedImageUrl; return next; });
                      setOriginalGeneratedImages(prev => { const next = [...prev]; next[index] = generatedImageUrl; return next; });
                  } catch (error) {
                      console.error(`Error generating image for style "${style}" (index ${index}):`, error);
                  } finally {
                      setIsGeneratingImages(prev => { const next = [...prev]; next[index] = false; return next; });
                  }
             }
          }
          generateSequentially();
      }
  };

  const handleLightingChange = (lighting: string) => {
      setActiveLighting(lighting);
      setGeneratedImages(Array(12).fill(null));
      setOriginalGeneratedImages(Array(12).fill(null));
      if (frontUserImage && sideUserImage && suggestedStyles.length > 0) {
          visualizeStyles(suggestedStyles, frontUserImage, sideUserImage, lighting);
          if (activeAngle === 'threeQuarter') {
               setTimeout(() => handleAngleChange('threeQuarter'), 4000); 
          }
      }
  };

  const processImageModification = async (
    modificationFn: (data: string, mimeType: string, param: string) => Promise<string>,
    param: string,
    sourceImages: (string | null)[]
  ) => {
    for (let i = 0; i < sourceImages.length; i++) {
        const imageUrl = sourceImages[i];
        if (!imageUrl) continue;

        setIsGeneratingImages(prev => { const next = [...prev]; next[i] = true; return next; });
        try {
              await new Promise(r => setTimeout(r, 200));
              const response = await fetch(imageUrl);
              const blob = await response.blob();
              const { data, mimeType } = await fileToDataUrl(new File([blob], `source.png`, { type: blob.type }));
              const modifiedImageUrl = await modificationFn(data, mimeType, param);
              setGeneratedImages(prev => { const next = [...prev]; next[i] = modifiedImageUrl; return next; });
          } catch (error) {
              console.error(`Error modifying image index ${i} with param ${param}:`, error);
          } finally {
              setIsGeneratingImages(prev => { const next = [...prev]; next[i] = false; return next; });
          }
    }
  };

  const handleColorChange = async (color: string) => {
    if (color === 'Natural') {
        setGeneratedImages(originalGeneratedImages);
        return;
    }
    await processImageModification(applyHairColor, color, originalGeneratedImages);
  };

  const handleHighlightsChange = async (color: string) => {
    if (color === 'None') {
        setGeneratedImages(originalGeneratedImages);
        return;
    }
    await processImageModification(applyHairHighlights, color, generatedImages);
  };

  const handleShare = async () => {
    if (!currentShop) return;
    const imagesToShareUrls = [];

    // Determine offset based on view
    let offset = 0;
    if (activeAngle === 'side') offset = 4;
    if (activeAngle === 'threeQuarter') offset = 8;

    // Try to gather generated images for current view
    for(let i=0; i<4; i++) {
        const idx = offset + i;
        if (generatedImages[idx] && suggestedStyles[i]) {
            imagesToShareUrls.push({ url: generatedImages[idx]!, name: suggestedStyles[i] });
        }
    }

    if (imagesToShareUrls.length === 0) {
        alert("No hay imágenes generadas para compartir.");
        return;
    }

    try {
        const files = await Promise.all(
            imagesToShareUrls.map(({url, name}) => 
                dataUrlToFile(url, `${name.replace(/\s+/g, '-')}-${activeAngle}.png`)
            )
        );

        if (navigator.canShare && navigator.canShare({ files })) {
            await navigator.share({
                title: 'Mi Nuevo Look de Barber Shop AI',
                text: `¡Mira estos nuevos estilos de cabello que ${currentShop.aiName} de ${currentShop.name} me sugirió!`,
                files: files,
            });
        } else {
             alert('Tu navegador no soporta compartir archivos. Inténtalo desde un dispositivo móvil.');
        }
    } catch (error) {
        console.error('Error sharing:', error);
        alert('Hubo un error al intentar compartir. Es posible que hayas cancelado la acción.');
    }
  };


  const handleSendMessage = async (userInput: string) => {
    if (!userInput.trim() || isAiLoading) return;

    const newUserMessage: Message = {
      id: Date.now().toString(),
      sender: 'user',
      text: userInput
    };
    setMessages((prevMessages) => [...prevMessages, newUserMessage]);
    setIsAiLoading(true);

    try {
      if (!chatSession.current) throw new Error("Chat session not initialized.");
      const stream = await chatSession.current.sendMessageStream({ message: userInput });
      let aiMessageId: string | null = null;
      let accumulatedText = "";
      for await (const chunk of stream) {
        accumulatedText += chunk.text;
        if (!aiMessageId) {
          aiMessageId = (Date.now() + 1).toString();
          setMessages((prev) => [...prev, { id: aiMessageId!, sender: 'ai', text: accumulatedText }]);
        } else {
          setMessages((prev) => prev.map((msg) => msg.id === aiMessageId ? { ...msg, text: accumulatedText } : msg));
        }
      }
    } catch (error) {
      console.error('Error sending message:', error);
      setMessages((prev) => [...prev, {
        id: 'error-send',
        sender: 'ai',
        text: '¡Ups! Algo salió mal. Por favor, intenta de nuevo.',
      }]);
    } finally {
      setIsAiLoading(false);
    }
  };

  const handleResetChat = () => {
    if(chatSession.current && currentShop) {
        initializeAndReset(currentShop);
    }
  };

  const handleOpenModal = (url: string, caption: string) => setModalImage({ url, caption });
  const handleCloseModal = () => setModalImage(null);

  const handleNavigate = (view: ActiveView) => {
      if (view === 'mirror' && appState === 'initial') {
        handleUploadNew();
      }
      setActiveView(view);
      setIsSidebarOpen(false);
  }

  const handleUpdateShopProfile = (updatedShop: BarberShop) => {
    setShops(prevShops => 
      prevShops.map(shop => shop.id === updatedShop.id ? updatedShop : shop)
    );
  };

  const handleUpdatePlan = (shopId: string, newPlan: 'Freemium' | 'Básico' | 'Profesional') => {
    setShops(prevShops =>
      prevShops.map(shop =>
        shop.id === shopId ? { ...shop, plan: newPlan } : shop
      )
    );
  };

  const handleUpdatePaymentMethod = (shopId: string, newMethod: PaymentMethod) => {
     setShops(prevShops =>
      prevShops.map(shop =>
        shop.id === shopId ? { ...shop, paymentMethod: newMethod } : shop
      )
    );
  };

  const viewTitles: { [key in ActiveView]: string } = {
    chat: 'Chat de Estilismo',
    mirror: 'Espejo Virtual',
    booking: 'Reservar Cita',
    bookingsList: 'Mis Reservas',
    shopProfile: 'Perfil de la Barbería',
    billing: 'Facturación y Plan',
    admin: 'Dashboard de Barbería',
    platformAdmin: 'Dashboard de Plataforma'
  };

  if (screen === 'home') {
    return <HomeView onShowLogin={handleShowLogin} onGoHome={handleGoHome} />;
  }
  if (screen === 'login') {
    return <LoginView onLogin={handleLogin} onGoHome={handleGoHome} />;
  }

  return (
    <div className="relative flex h-screen bg-gray-100 text-gray-800 font-sans overflow-hidden">
      {modalImage && <ImageModal imageUrl={modalImage.url} caption={modalImage.caption} onClose={handleCloseModal} />}

      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-30 lg:hidden"
          onClick={() => setIsSidebarOpen(false)}
          aria-hidden="true"
        ></div>
      )}

      <Sidebar 
        currentUser={currentUser}
        currentShop={currentShop}
        onResetChat={handleResetChat}
        activeView={activeView}
        onNavigate={handleNavigate}
        isOpen={isSidebarOpen}
        setIsOpen={setIsSidebarOpen}
        onLogout={handleLogout}
        onGoHome={handleGoHome}
      />

      <div className="flex-1 flex flex-col overflow-hidden">
         <MainHeader 
            title={viewTitles[activeView]} 
            onMenuClick={() => setIsSidebarOpen(true)}
        />
        <main className="flex-1 overflow-y-auto">
            {currentUser?.role === 'platformAdmin' && activeView === 'platformAdmin' && (
              <PlatformAdminView shops={shops} bookings={bookings} />
            )}
            {currentUser?.role === 'shopOwner' && currentShop && (
                <>
                    {activeView === 'chat' && (
                      <ChatView 
                        messages={messages}
                        isAiLoading={isAiLoading}
                        onSendMessage={handleSendMessage}
                        appState={appState}
                      />
                    )}
                    {activeView === 'mirror' && (
                      <MirrorView 
                        appState={appState}
                        isAiLoading={isAiLoading}
                        onPhotosReady={handlePhotosReady}
                        currentShopName={currentShop.name}
                        aiName={currentShop.aiName}
                        frontUserImageUrl={frontUserImage?.url ?? null}
                        sideUserImageUrl={sideUserImage?.url ?? null}
                        generatedImages={generatedImages}
                        suggestedStyles={suggestedStyles}
                        analysisResult={analysisResult}
                        isGeneratingImages={isGeneratingImages}
                        activeAngle={activeAngle}
                        onAngleChange={handleAngleChange}
                        onLightingChange={handleLightingChange}
                        onColorChange={handleColorChange}
                        onHighlightsChange={handleHighlightsChange}
                        onRegenerateImage={handleRegenerateSingleImage}
                        onShare={handleShare}
                        onUploadNew={handleUploadNew}
                        onImageClick={handleOpenModal}
                      />
                    )}
                    {activeView === 'booking' && (
                      <BookingView 
                        shop={currentShop} 
                        onBookingConfirmed={handleAddBooking} 
                        userId={firebaseUser?.uid || 'anon'}
                      />
                    )}
                    {activeView === 'bookingsList' && (
                        <BookingsListView bookings={bookings} onNavigate={handleNavigate} />
                    )}
                    {activeView === 'shopProfile' && (
                        <ShopProfileView shop={currentShop} onUpdateProfile={handleUpdateShopProfile} />
                    )}
                    {activeView === 'billing' && (
                        <BillingView 
                          shop={currentShop} 
                          onUpdatePlan={handleUpdatePlan} 
                          onUpdatePaymentMethod={handleUpdatePaymentMethod} 
                        />
                    )}
                    {activeView === 'admin' && (
                        <AdminView currentShop={currentShop} bookings={bookings} />
                    )}
                </>
            )}
        </main>
      </div>
    </div>
  );
};

export default App;

