import React, { useState } from 'react';
import { loginWithEmail, loginWithGoogle, registerWithEmail } from '../services/firebaseService';

interface LoginViewProps {
  onLogin: (user: any, role: 'platformAdmin' | 'shopOwner') => void;
  onGoHome: () => void;
}

const GoogleIcon = () => (
    <svg className="w-5 h-5 mr-3" viewBox="0 0 48 48">
        <path fill="#FFC107" d="M43.611 20.083H42V20H24v8h11.303c-1.649 4.657-6.08 8-11.303 8c-6.627 0-12-5.373-12-12s5.373-12 12-12c3.059 0 5.842 1.154 7.961 3.039l5.657-5.657C34.046 6.053 29.268 4 24 4C12.955 4 4 12.955 4 24s8.955 20 20 20s20-8.955 20-20c0-1.341-.138-2.65-.389-3.917z"></path>
        <path fill="#FF3D00" d="M6.306 14.691l6.571 4.819C14.655 15.108 18.961 12 24 12c3.059 0 5.842 1.154 7.961 3.039l5.657-5.657C34.046 6.053 29.268 4 24 4C16.318 4 9.656 8.337 6.306 14.691z"></path>
        <path fill="#4CAF50" d="M24 44c5.166 0 9.86-1.977 13.409-5.192l-6.19-5.238C29.211 35.091 26.715 36 24 36c-5.222 0-9.619-3.317-11.283-7.946l-6.522 5.025C9.505 39.556 16.227 44 24 44z"></path>
        <path fill="#1976D2" d="M43.611 20.083H42V20H24v8h11.303c-.792 2.237-2.231 4.166-4.087 5.571l6.19 5.238C39.986 36.657 44 30.836 44 24c0-1.341-.138-2.65-.389-3.917z"></path>
    </svg>
);

const LoginView: React.FC<LoginViewProps> = ({ onLogin, onGoHome }) => {
  const [isRegistering, setIsRegistering] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [role, setRole] = useState<'platformAdmin' | 'shopOwner'>('shopOwner');
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const handleRoleChange = (newRole: 'platformAdmin' | 'shopOwner') => {
      setRole(newRole);
      // Disable registration mode if switching to Platform Admin
      if (newRole === 'platformAdmin') {
          setIsRegistering(false);
      }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setLoading(true);

    try {
        let userCredential;
        if (isRegistering) {
            userCredential = await registerWithEmail(email, password, name);
        } else {
            userCredential = await loginWithEmail(email, password);
        }
        // For this demo, we pass the selected role manually since we aren't managing roles in DB yet
        onLogin(userCredential.user, role);
    } catch (err: any) {
        console.error(err);
        setError(err.message || 'Ocurrió un error. Revisa tus credenciales.');
    } finally {
        setLoading(false);
    }
  };

  const handleGoogleLogin = async () => {
      setError(null);
      try {
          const userCredential = await loginWithGoogle();
          onLogin(userCredential.user, role);
      } catch (err: any) {
          console.error(err);
          setError('Error al iniciar con Google.');
      }
  };

  return (
    <div className="min-h-screen bg-gray-900 flex items-center justify-center p-4">
      <div className="w-full max-w-5xl mx-auto grid md:grid-cols-2 shadow-2xl rounded-lg overflow-hidden">
        {/* Left Side: Image and Branding */}
        <div className="hidden md:block relative">
            <img 
                src="https://images.pexels.com/photos/3998429/pexels-photo-3998429.jpeg?auto=compress&cs=tinysrgb&w=1260&h=750&dpr=2" 
                alt="Barber applying product to a client's hair" 
                className="w-full h-full object-cover"
            />
            <div className="absolute inset-0 bg-black bg-opacity-60 flex flex-col justify-end p-10 text-white">
                <button onClick={onGoHome} className="text-left focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-black focus:ring-red-500 rounded-lg p-1">
                    <h1 className="text-4xl font-bold tracking-wider">
                        Barber Shop
                        <span className="ml-2 bg-gradient-to-r from-red-500 to-red-600 text-transparent bg-clip-text font-black italic">
                            AI
                        </span>
                    </h1>
                </button>
                <p className="mt-4 text-lg text-gray-300">La herramienta definitiva para la barbería moderna.</p>
            </div>
        </div>

        {/* Right Side: Login Form */}
        <div className="bg-white p-8 md:p-12 flex flex-col justify-center">
            <div className="w-full max-w-md mx-auto">
                 <h2 className="text-3xl font-bold text-gray-800 mb-2">{isRegistering ? 'Crear Cuenta' : 'Bienvenido de Nuevo'}</h2>
                 <p className="text-gray-500 mb-6">Ingresa tus datos para continuar.</p>

                 {/* Role Selector (Simulated for Demo) */}
                 <div className="mb-6 flex bg-gray-100 p-1 rounded-lg">
                    <button 
                        type="button"
                        onClick={() => handleRoleChange('shopOwner')}
                        className={`flex-1 py-2 text-sm font-semibold rounded-md transition-colors ${role === 'shopOwner' ? 'bg-white text-red-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
                    >
                        Dueño de Barbería
                    </button>
                    <button 
                        type="button"
                        onClick={() => handleRoleChange('platformAdmin')}
                        className={`flex-1 py-2 text-sm font-semibold rounded-md transition-colors ${role === 'platformAdmin' ? 'bg-white text-red-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
                    >
                        Admin Plataforma
                    </button>
                 </div>

                <form onSubmit={handleSubmit}>
                    <div className="space-y-4">
                         {isRegistering && (
                            <div>
                                <label htmlFor="name" className="block text-sm font-medium text-gray-700">Nombre Completo</label>
                                <input 
                                    type="text" 
                                    id="name"
                                    value={name}
                                    onChange={(e) => setName(e.target.value)}
                                    required={isRegistering}
                                    className="mt-1 block w-full px-4 py-3 bg-gray-50 border border-gray-300 rounded-md shadow-sm text-gray-900 focus:outline-none focus:ring-red-500 focus:border-red-500"
                                />
                            </div>
                        )}
                        <div>
                            <label htmlFor="email" className="block text-sm font-medium text-gray-700">Correo Electrónico</label>
                            <input 
                                type="email" 
                                id="email"
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                                required
                                className="mt-1 block w-full px-4 py-3 bg-gray-50 border border-gray-300 rounded-md shadow-sm text-gray-900 focus:outline-none focus:ring-red-500 focus:border-red-500"
                            />
                        </div>
                         <div>
                            <label htmlFor="password" className="block text-sm font-medium text-gray-700">Contraseña</label>
                            <input 
                                type="password" 
                                id="password"
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                required
                                className="mt-1 block w-full px-4 py-3 bg-gray-50 border border-gray-300 rounded-md shadow-sm text-gray-900 focus:outline-none focus:ring-red-500 focus:border-red-500"
                            />
                        </div>

                        {error && <p className="text-red-500 text-sm">{error}</p>}

                        <div>
                            <button 
                                type="submit" 
                                disabled={loading}
                                className="w-full flex justify-center py-3 px-4 border border-transparent rounded-md shadow-sm text-lg font-bold text-white bg-red-600 hover:bg-red-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-red-500 transition-transform transform hover:scale-105 disabled:bg-red-400"
                            >
                                {loading ? 'Procesando...' : isRegistering ? 'Registrarse' : 'Ingresar'}
                            </button>
                        </div>
                    </div>
                </form>

                <div className="my-6 flex items-center">
                    <div className="flex-grow border-t border-gray-300"></div>
                    <span className="flex-shrink mx-4 text-sm text-gray-500">O continúa con</span>
                    <div className="flex-grow border-t border-gray-300"></div>
                </div>

                <div className="grid grid-cols-1 gap-4">
                    <button onClick={handleGoogleLogin} className="w-full inline-flex items-center justify-center py-2.5 px-4 border border-gray-300 rounded-md shadow-sm bg-white text-sm font-medium text-gray-700 hover:bg-gray-50">
                        <GoogleIcon />
                        Continuar con Google
                    </button>
                </div>

                {role !== 'platformAdmin' && (
                  <p className="mt-8 text-center text-sm text-gray-600">
                      {isRegistering ? '¿Ya tienes cuenta?' : '¿No tienes una cuenta?'} 
                      <button onClick={() => setIsRegistering(!isRegistering)} className="ml-1 font-medium text-red-600 hover:underline focus:outline-none">
                          {isRegistering ? 'Inicia Sesión' : 'Crear cuenta'}
                      </button>
                  </p>
                )}
            </div>
        </div>
      </div>
    </div>
  );
};

export default LoginView;

