// --- Auth Services (REAL) ---

export const loginWithEmail = async (email: string, password: string): Promise<{ user: any }> => {
    if (!auth) throw new Error("Firebase Auth not initialized");
    const userCredential = await auth.signInWithEmailAndPassword(email, password);
    return { user: userCredential.user };
};

export const registerWithEmail = async (email: string, password: string, name: string): Promise<{ user: any }> => {
    if (!auth) throw new Error("Firebase Auth not initialized");
    const userCredential = await auth.createUserWithEmailAndPassword(email, password);
    // Update the user's display name
    if (userCredential.user) {
        await userCredential.user.updateProfile({
            displayName: name
        });
    }
    return { user: userCredential.user };
};

export const loginWithGoogle = async (): Promise<{ user: any }> => {
    if (!auth) throw new Error("Firebase Auth not initialized");
    const provider = new firebase.auth.GoogleAuthProvider();
    const userCredential = await auth.signInWithPopup(provider);
    return { user: userCredential.user };
};

export const logoutUser = async () => {
    if (!auth) return;
    await auth.signOut();
};

// --- Firestore Data Services (REAL) ---

export const saveBookingToFirestore = async (booking: Omit<Booking, 'id'>) => {
    if (!db) throw new Error("Firestore not initialized");

    // Add a timestamp to sort later if needed
    const docRef = await db.collection("bookings").add({
        ...booking,
        createdAt: new Date().toISOString()
    });
    return docRef.id;
};

export const subscribeToUserBookings = (userId: string, callback: (bookings: Booking[]) => void) => {
    if (!db) return () => {};

    // v8 syntax
    const unsubscribe = db.collection("bookings")
        .where("userId", "==", userId)
        // You can add orderBy("createdAt", "desc") here if you create a composite index in Firebase Console
        .onSnapshot((querySnapshot) => {
            const bookings: Booking[] = [];
            querySnapshot.forEach((doc) => {
                bookings.push({ id: doc.id, ...doc.data() } as Booking);
            });
            callback(bookings);
        });

    return unsubscribe;
};

export const subscribeToShopBookings = (shopName: string, callback: (bookings: Booking[]) => void) => {
    if (!db) return () => {};

    const unsubscribe = db.collection("bookings")
        .where("shopName", "==", shopName)
        .onSnapshot((querySnapshot) => {
            const bookings: Booking[] = [];
            querySnapshot.forEach((doc) => {
                bookings.push({ id: doc.id, ...doc.data() } as Booking);
            });
            callback(bookings);
        });

    return unsubscribe;
};

