import React, { useState } from 'react';
import { BarberShop, Booking } from '../types';
import { getAvailableSlots, sendBookingConfirmationEmail } from '../services/geminiService';
import { saveBookingToFirestore } from '../services/firebaseService';

interface BookingViewProps {
  shop: BarberShop;
  userId: string;
  userEmail: string; // Add email prop
  onBookingConfirmed: (bookingDetails: Omit<Booking, 'id'>) => void;
}

const services = ["Corte de Pelo", "Afeitado Clásico", "Arreglo de Barba", "Corte y Barba"];

const BookingView: React.FC<BookingViewProps> = ({ shop, userId, userEmail, onBookingConfirmed }) => {
  const [step, setStep] = useState(1);
  const [selectedService, setSelectedService] = useState(services[0]);
  const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0]);
  const [selectedSlot, setSelectedSlot] = useState<string | null>(null);
  const [availableSlots, setAvailableSlots] = useState<string[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleFindSlots = async () => {
    setIsLoading(true);
    setError(null);
    setAvailableSlots([]);
    try {
      const slots = await getAvailableSlots(selectedDate, selectedService, shop);
      setAvailableSlots(slots);
      setStep(2);
    } catch (e) {
      setError('No se pudieron cargar los horarios. Por favor, inténtalo de nuevo.');
      console.error(e);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSelectSlot = (slot: string) => {
    setSelectedSlot(slot);
    setStep(3);
  };

  const handleConfirmBooking = async () => {
    if (selectedSlot) {
      setIsLoading(true);
      try {
          const bookingData = {
            shopName: shop.name,
            service: selectedService,
            date: selectedDate,
            time: selectedSlot,
            userId: userId
          };

          // 1. Save to database
          await saveBookingToFirestore(bookingData);

          // 2. Send email confirmation (don't block UI if it fails)
          if (userEmail) {
            sendBookingConfirmationEmail(userEmail, bookingData).catch(e => console.error("Error sending email:", e));
          }

          onBookingConfirmed(bookingData);
          setStep(4);
      } catch (e) {
          console.error(e);
          setError("Error al guardar la reserva. Intenta de nuevo.");
      } finally {
          setIsLoading(false);
      }
    }
  };

  const handleReset = () => {
    setStep(1);
    setSelectedSlot(null);
    setAvailableSlots([]);
    setError(null);
  };

  return (
    <div className="w-full h-full flex flex-col items-center justify-center p-6 bg-gray-50">
      <div className="w-full max-w-2xl bg-white rounded-xl shadow-lg p-8 border border-gray-200">
        <h2 className="text-3xl font-bold text-gray-800 mb-2 text-center">Reservar Cita</h2>
        <p className="text-center text-gray-500 mb-8">en <span className="font-semibold">{shop.name}</span></p>

        {step === 1 && (
          <div className="space-y-6 animate-fade-in">
            <div>
              <label htmlFor="service" className="block text-sm font-medium text-gray-700 mb-1">Servicio</label>
              <select id="service" value={selectedService} onChange={e => setSelectedService(e.target.value)} className="w-full p-3 bg-white text-gray-900 border border-gray-300 rounded-md focus:ring-red-500 focus:border-red-500">
                {services.map(s => <option key={s} value={s}>{s}</option>)}
              </select>
            </div>
            <div>
              <label htmlFor="date" className="block text-sm font-medium text-gray-700 mb-1">Fecha</label>
              <input type="date" id="date" value={selectedDate} onChange={e => setSelectedDate(e.target.value)} min={new Date().toISOString().split('T')[0]} className="w-full p-3 bg-white text-gray-900 border border-gray-300 rounded-md focus:ring-red-500 focus:border-red-500" />
            </div>
            <button onClick={handleFindSlots} disabled={isLoading} className="w-full bg-red-600 text-white font-bold py-3 rounded-lg hover:bg-red-700 transition-colors disabled:bg-red-300">
              {isLoading ? 'Buscando...' : 'Buscar Horarios'}
            </button>
            {error && <p className="text-red-500 text-center mt-4">{error}</p>}
          </div>
        )}

        {step === 2 && (
          <div className="animate-fade-in">
             <h3 className="text-xl font-semibold text-center mb-4">Selecciona un horario</h3>
             {availableSlots.length > 0 ? (
                <div className="grid grid-cols-3 sm:grid-cols-4 gap-3">
                    {availableSlots.map(slot => (
                        <button key={slot} onClick={() => handleSelectSlot(slot)} className="p-3 bg-gray-100 text-gray-800 rounded-md text-center font-semibold hover:bg-red-600 hover:text-white transition-colors">
                            {slot}
                        </button>
                    ))}
                </div>
             ) : (
                <p className="text-center text-gray-500 py-8">No hay horarios disponibles para este día. Por favor, elige otra fecha.</p>
             )}
             <button onClick={handleReset} className="w-full mt-6 bg-gray-200 text-gray-700 font-bold py-3 rounded-lg hover:bg-gray-300 transition-colors">Volver</button>
          </div>
        )}

        {step === 3 && selectedSlot && (
            <div className="text-center animate-fade-in">
                <h3 className="text-2xl font-bold mb-4">Confirma tu Cita</h3>
                <div className="bg-gray-50 p-6 rounded-lg space-y-2 border border-gray-200 text-left">
                    <p><strong className="text-gray-600">Servicio:</strong> {selectedService}</p>
                    <p><strong className="text-gray-600">Fecha:</strong> {new Date(selectedDate + 'T00:00:00').toLocaleDateString('es-ES', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}</p>
                    <p><strong className="text-gray-600">Hora:</strong> {selectedSlot}</p>
                    <p><strong className="text-gray-600">Barbería:</strong> {shop.name}</p>
                    <p><strong className="text-gray-600">Email de confirmación:</strong> {userEmail || "No disponible"}</p>
                </div>
                 <div className="flex gap-4 mt-6">
                    <button onClick={() => setStep(2)} disabled={isLoading} className="flex-1 bg-gray-200 text-gray-700 font-bold py-3 rounded-lg hover:bg-gray-300 transition-colors">Cambiar Hora</button>
                    <button onClick={handleConfirmBooking} disabled={isLoading} className="flex-1 bg-red-600 text-white font-bold py-3 rounded-lg hover:bg-red-700 transition-colors disabled:bg-red-400">
                        {isLoading ? 'Guardando...' : 'Confirmar Reserva'}
                    </button>
                </div>
                {error && <p className="text-red-500 mt-4">{error}</p>}
            </div>
        )}

        {step === 4 && selectedSlot && (
            <div className="text-center animate-fade-in">
                <div className="w-20 h-20 bg-green-100 rounded-full mx-auto flex items-center justify-center mb-4">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 text-green-600" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
                </div>
                <h3 className="text-2xl font-bold">¡Reserva Confirmada!</h3>
                <p className="text-gray-600 mt-2">Te esperamos en {shop.name} el {new Date(selectedDate + 'T00:00:00').toLocaleDateString()} a las {selectedSlot}.</p>
                {userEmail && <p className="text-sm text-gray-500 mt-2">Hemos enviado un correo de confirmación a {userEmail}</p>}
                <button onClick={handleReset} className="mt-6 bg-red-600 text-white font-bold py-3 px-8 rounded-lg hover:bg-red-700 transition-colors">Hacer otra reserva</button>
            </div>
        )}

      </div>
       <style>{`
        @keyframes fade-in {
          from { opacity: 0; transform: translateY(10px); }
          to { opacity: 1; transform: translateY(0); }
        }
        .animate-fade-in {
          animation: fade-in 0.3s ease-out forwards;
        }
      `}</style>
    </div>
  );
};

