                  <h3 className="text-2xl font-bold text-gray-800 mb-6 text-center">Compara Nuestros Planes</h3>
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                      {(Object.keys(plans) as PlanName[]).map((name) => {
