const MOCK_SERVICES_WITH_PRICES: { [key: string]: number } = {
  "Corte de Pelo": 40,
  "Afeitado Clásico": 35,
  "Arreglo de Barba": 25,
  "Corte y Barba": 60,
  'Corte Clásico (Pompadour, Side-Part)': 45,
  'Afeitado a Navaja Tradicional': 40,
  'Arreglo de Barba Premium': 30,
  'El Paquete Dapper (Corte y Afeitado)': 80,
  'Skin Fade / Taper Fade': 40,
  'Corte Texturizado / Crop Top': 45,
  'Diseño de Cabello (Hair Tattoo)': 25,
  'Corte a Tijera y Navaja': 50,
  'Afeitado Ritual con Toalla Caliente': 55,
  'Arreglo de Bigote y Barba': 35,
  'Tratamiento Capilar Fortificante': 40,
};

const PLAN_PRICES = {
  'Freemium': 0,
  'Básico': 1.99,
  'Profesional': 9.99,
};

// Pseudo-random number generator function based on a seed string
// This ensures charts look consistent for the same shop every time you visit
const seededRandom = (seedStr: string) => {
  let hash = 0;
  for (let i = 0; i < seedStr.length; i++) {
    const char = seedStr.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash; // Convert to 32bit integer
  }
  const x = Math.sin(hash) * 10000;
  return x - Math.floor(x);
};

export const getAdminDashboardData = (shop: BarberShop, bookings: Booking[]): AdminDashboardData => {
  const shopBookings = bookings.filter(b => b.shopName === shop.name);

  // Stats - Deterministic based on shop ID length and name
  const baseRandom = seededRandom(shop.id + shop.name);

  const totalBookings = shopBookings.length > 0 ? shopBookings.length : Math.floor(baseRandom * 50) + 10;
  // Simulate analyses based on bookings
  const totalAnalyses = Math.floor(totalBookings * (1.5 + baseRandom)); 

  const serviceCounts: { [key: string]: number } = {};
  let monthlyRevenue = 0;

  // If no real bookings, generate mock service distribution
  if (shopBookings.length === 0) {
      shop.services.forEach((s, idx) => {
          const count = Math.floor(seededRandom(shop.id + s.name) * 20);
          serviceCounts[s.name] = count;
          const price = parseInt(s.price.replace('$','')) || 30;
          monthlyRevenue += count * price;
      });
  } else {
      shopBookings.forEach(b => {
        serviceCounts[b.service] = (serviceCounts[b.service] || 0) + 1;
        monthlyRevenue += MOCK_SERVICES_WITH_PRICES[b.service] || 30; 
      });
  }

  const mostPopularService = Object.keys(serviceCounts).length > 0 
    ? Object.keys(serviceCounts).reduce((a, b) => serviceCounts[a] > serviceCounts[b] ? a : b)
    : 'Corte Clásico';

  // Daily Activity for the last 7 days
  const dailyActivity = Array.from({ length: 7 }).map((_, i) => {
    const date = new Date();
    date.setDate(date.getDate() - (6 - i));
    const day = date.toLocaleDateString('es-ES', { weekday: 'short' });
    const dateStr = date.toISOString().split('T')[0];

    // Consistent seed for this specific day and shop
    const dailySeed = shop.id + dateStr;
    const rng = seededRandom(dailySeed);

    const analyses = Math.floor(rng * 15) + 2;
    const bookingsToday = shopBookings.filter(b => b.date === dateStr).length + Math.floor(rng * 5);

    return { day, Analyses: analyses, Bookings: bookingsToday };
  });

  // Service Distribution
  const serviceDistribution = Object.entries(serviceCounts)
    .map(([name, count]) => ({ name, count }))
    .sort((a,b) => b.count - a.count);

  // Recent Activity construction
  const recentBookings: RecentActivity[] = shopBookings.slice(-5).map(b => ({
    id: `b-${b.id}`,
    type: 'booking',
    description: `Nueva reserva para ${b.service} a las ${b.time}`,
    time: new Date(b.date).toLocaleDateString('es-ES', { month: 'short', day: 'numeric' }),
    icon: 'calendar',
  }));

  // Simulate recent analyses based on consistent data
  const recentAnalyses: RecentActivity[] = Array.from({length: 5}).map((_, i) => {
      const time = new Date();
      time.setHours(time.getHours() - i * 2);
      // Use shop.id to keep IDs consistent across renders
      return {
        id: `a-${i}-${shop.id}`,
        type: 'analysis',
        description: `Análisis de estilo de IA completado`,
        time: `${time.getHours()}:${String(time.getMinutes()).padStart(2, '0')}`,
        icon: 'sparkles',
      }
  });

  // Merge and sort slightly deterministically
  let recentActivity = [...recentBookings, ...recentAnalyses];
  // Simple deterministic sort based on ID char codes to keep order static on refresh
  recentActivity.sort((a, b) => b.id.charCodeAt(0) - a.id.charCodeAt(0)); 
  recentActivity = recentActivity.slice(0, 8);


  return {
    stats: {
      totalAnalyses,
      totalBookings,
      mostPopularService,
      monthlyRevenue,
    },
    dailyActivity,
    serviceDistribution,
    recentActivity,
  };
};


export const getPlatformDashboardData = (shops: BarberShop[], bookings: Booking[]): PlatformDashboardData => {
  // Platform-wide stats
  const totalShops = shops.length;
  const totalPlatformBookings = bookings.length > 0 ? bookings.length : 142; // Mock base
  const totalPlatformAnalyses = Math.floor(totalPlatformBookings * 2.5);

  let monthlyRecurringRevenue = 0;
  const planCounts = { 'Freemium': 0, 'Básico': 0, 'Profesional': 0 };

  shops.forEach(shop => {
      monthlyRecurringRevenue += PLAN_PRICES[shop.plan];
      planCounts[shop.plan]++;
  });

  // Add some mock revenue if shop list is small for demo purposes
  if (monthlyRecurringRevenue < 50) monthlyRecurringRevenue += 1250;

  const planDistribution: PlanDistribution[] = [
    { name: 'Freemium', count: planCounts['Freemium'], color: '#9ca3af' }, // gray-400
    { name: 'Básico', count: planCounts['Básico'], color: '#f59e0b' }, // amber-500
    { name: 'Profesional', count: planCounts['Profesional'], color: '#ef4444' }, // red-500
  ];

  // Get last 3 shops as "recently joined"
  const recentlyJoined = shops.slice(-3).reverse();

  return {
    stats: {
      monthlyRecurringRevenue,
      totalShops,
      totalPlatformAnalyses,
      totalPlatformBookings,
    },
    planDistribution,
    recentlyJoined,
  };
};

import React, { useState, useEffect } from 'react';
import { PaymentMethod } from '../types';
import { CreditCardIcon, PayPalIcon, ZelleIcon, ChaseIcon } from '../assets/icons';

type PlanName = 'Freemium' | 'Básico' | 'Profesional';
type ModalContext = { type: 'changePlan' | 'updatePayment', plan?: PlanName } | null;
type PaymentProvider = 'card' | 'paypal' | 'zelle' | 'chase';

interface PaymentModalProps {
  isOpen: boolean;
  onClose: () => void;
  context: ModalContext;
  currentPlan: PlanName;
  onSuccess: (newPlan?: PlanName, newPaymentMethod?: PaymentMethod) => void;
}

const plansInfo = {
  'Freemium': { price: '$0', priceNum: 0 },
  'Básico': { price: '$1.99', priceNum: 1.99 },
  'Profesional': { price: '$9.99', priceNum: 9.99 },
};

const PaymentModal: React.FC<PaymentModalProps> = ({ isOpen, onClose, context, currentPlan, onSuccess }) => {
  const [activeProvider, setActiveProvider] = useState<PaymentProvider>('card');
  const [cardDetails, setCardDetails] = useState({ number: '', expiry: '', cvc: '', name: '' });
  const [isProcessing, setIsProcessing] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);

  useEffect(() => {
    // Reset state when modal is opened/closed or context changes
    setActiveProvider('card');
    setCardDetails({ number: '', expiry: '', cvc: '', name: '' });
    setIsProcessing(false);
    setIsSuccess(false);
  }, [isOpen, context]);

  if (!isOpen || !context) return null;

  const { type, plan: newPlan } = context;
  const isChangingPlan = type === 'changePlan' && newPlan && newPlan !== currentPlan;

  const title = isChangingPlan ? `Actualizar a Plan ${newPlan}` : 'Actualizar Método de Pago';
  const amount = isChangingPlan ? plansInfo[newPlan!].priceNum : 0;
  const buttonText = isChangingPlan ? `Pagar ${plansInfo[newPlan!].price}` : 'Guardar Tarjeta';

  const handleCardInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    let { name, value } = e.target;
    // Formatting logic
    if (name === 'number') {
      value = value.replace(/\D/g, '').replace(/(.{4})/g, '$1 ').trim().slice(0, 19);
    } else if (name === 'expiry') {
      value = value.replace(/\D/g, '').replace(/(.{2})/, '$1/').trim().slice(0, 5);
    } else if (name === 'cvc') {
      value = value.replace(/\D/g, '').slice(0, 4);
    }
    setCardDetails(prev => ({ ...prev, [name]: value }));
  };

  const isFormValid = cardDetails.number.length === 19 && cardDetails.expiry.length === 5 && cardDetails.cvc.length >= 3 && cardDetails.name.trim() !== '';

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (activeProvider === 'card' && !isFormValid) return;

    setIsProcessing(true);
    setTimeout(() => {
      setIsProcessing(false);
      setIsSuccess(true);

      const newPaymentMethod: PaymentMethod | undefined = activeProvider === 'card' ? {
        type: cardDetails.number.startsWith('4') ? 'Visa' : cardDetails.number.startsWith('5') ? 'Mastercard' : 'Amex',
        last4: cardDetails.number.slice(-4),
        expiry: cardDetails.expiry
      } : undefined;

      setTimeout(() => {
          onSuccess(isChangingPlan ? newPlan : undefined, newPaymentMethod);
      }, 1500); // Wait a bit on the success screen

    }, 2000); // Simulate network delay
  };

  const renderProviderContent = () => {
      switch (activeProvider) {
          case 'card':
              return (
                  <form onSubmit={handleSubmit} className="space-y-4">
                      <div className="space-y-1">
                          <label htmlFor="card-name" className="text-sm font-medium text-gray-600">Nombre en la tarjeta</label>
                          <input id="card-name" name="name" type="text" value={cardDetails.name} onChange={handleCardInputChange} placeholder="John Doe" required className="w-full p-2.5 border border-gray-300 rounded-md focus:ring-red-500 focus:border-red-500"/>
                      </div>
                      <div className="space-y-1">
                          <label htmlFor="card-number" className="text-sm font-medium text-gray-600">Número de tarjeta</label>
                          <input id="card-number" name="number" type="text" value={cardDetails.number} onChange={handleCardInputChange} placeholder="0000 0000 0000 0000" required className="w-full p-2.5 border border-gray-300 rounded-md focus:ring-red-500 focus:border-red-500"/>
                      </div>
                      <div className="flex gap-4">
                          <div className="w-1/2 space-y-1">
                              <label htmlFor="card-expiry" className="text-sm font-medium text-gray-600">Expiración</label>
                              <input id="card-expiry" name="expiry" type="text" value={cardDetails.expiry} onChange={handleCardInputChange} placeholder="MM/YY" required className="w-full p-2.5 border border-gray-300 rounded-md focus:ring-red-500 focus:border-red-500"/>
                          </div>
                          <div className="w-1/2 space-y-1">
                              <label htmlFor="card-cvc" className="text-sm font-medium text-gray-600">CVC</label>
                              <input id="card-cvc" name="cvc" type="text" value={cardDetails.cvc} onChange={handleCardInputChange} placeholder="123" required className="w-full p-2.5 border border-gray-300 rounded-md focus:ring-red-500 focus:border-red-500"/>
                          </div>
                      </div>
                      <button type="submit" disabled={!isFormValid} className="w-full mt-4 bg-red-600 text-white font-bold py-3 rounded-lg hover:bg-red-700 transition-colors disabled:bg-red-300">
                          {buttonText}
                      </button>
                  </form>
              );
          case 'paypal':
              return <div className="text-center p-8 border rounded-lg bg-gray-50"><p className="text-gray-600">Serás redirigido a PayPal para completar tu pago de forma segura.</p><button onClick={handleSubmit} className="mt-4 w-full bg-blue-600 text-white font-bold py-3 rounded-lg hover:bg-blue-700">Continuar a PayPal</button></div>;
          case 'zelle':
              return <div className="text-center p-6 border rounded-lg bg-purple-50"><h4 className="font-bold">Pago con Zelle</h4><p className="text-gray-700 mt-2">Envía <strong className="text-purple-800">{plansInfo[newPlan!]?.price}</strong> a <strong className="text-purple-800">pagos@barberai.com</strong> y tu plan se activará en 24h.</p></div>;
          case 'chase':
              return <div className="text-center p-6 border rounded-lg bg-blue-50"><h4 className="font-bold">Pago con Chase</h4><p className="text-gray-700 mt-2">Realiza una transferencia por <strong className="text-blue-800">{plansInfo[newPlan!]?.price}</strong> a la cuenta #123456789 en Chase.</p></div>;
      }
  }

  const renderContent = () => {
    if (isProcessing) {
      return (
        <div className="flex flex-col items-center justify-center h-48">
          <div className="w-12 h-12 border-4 border-red-500 border-t-transparent rounded-full animate-spin"></div>
          <p className="mt-4 font-semibold text-gray-700">Procesando pago...</p>
        </div>
      );
    }
    if (isSuccess) {
      return (
         <div className="flex flex-col items-center justify-center h-48 text-center">
            <div className="w-16 h-16 bg-green-100 rounded-full flex items-center justify-center">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 text-green-600" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
            </div>
            <h3 className="text-xl font-bold mt-4">¡Pago Exitoso!</h3>
            <p className="text-gray-600 mt-1">{isChangingPlan ? `Tu plan ha sido actualizado a ${newPlan}.` : 'Tu método de pago ha sido guardado.'}</p>
        </div>
      );
    }
    return (
        <>
            <div className="grid grid-cols-4 gap-2 mb-6">
                {(['card', 'paypal', 'zelle', 'chase'] as PaymentProvider[]).map(p => (
                    <button key={p} onClick={() => setActiveProvider(p)} className={`p-3 border rounded-lg flex items-center justify-center transition-all ${activeProvider === p ? 'bg-red-50 border-red-500 ring-2 ring-red-200' : 'bg-white hover:bg-gray-50'}`}>
                        {p === 'card' && <CreditCardIcon className="w-8 h-8 text-gray-600" />}
                        {p === 'paypal' && <PayPalIcon className="w-8 h-8 text-blue-800" />}
                        {p === 'zelle' && <ZelleIcon className="w-8 h-8 text-purple-700" />}
                        {p === 'chase' && <ChaseIcon className="w-8 h-8 text-blue-600" />}
                    </button>
                ))}
            </div>
            {renderProviderContent()}
        </>
    );
  }

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4" onClick={onClose} role="dialog">
      <div className="bg-white rounded-lg shadow-xl p-6 w-full max-w-md m-4 relative" onClick={(e) => e.stopPropagation()}>
        <button onClick={onClose} className="absolute top-3 right-3 p-1 text-gray-500 hover:text-gray-800" aria-label="Cerrar">&times;</button>
        <h3 className="text-xl font-bold text-gray-800 mb-4">{title}</h3>
        {renderContent()}
      </div>
    </div>
  );
};

