const LoginView: React.FC<LoginViewProps> = ({ onLogin, onGoHome }) => {
  const [isRegistering, setIsRegistering] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [role, setRole] = useState<'platformAdmin' | 'shopOwner'>('shopOwner');
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const handleRoleChange = (newRole: 'platformAdmin' | 'shopOwner') => {
      setRole(newRole);
      // Disable registration mode if switching to Platform Admin
      if (newRole === 'platformAdmin') {
          setIsRegistering(false);
      }
  };

  const getFriendlyErrorMessage = (err: any) => {
    console.error("Login Error:", err);
    if (err.code === 'auth/unauthorized-domain') {
        return 'DOMINIO NO AUTORIZADO: Agrega este dominio en Firebase Console -> Authentication -> Settings -> Authorized Domains.';
    }
    if (err.code === 'auth/invalid-credential' || err.code === 'auth/user-not-found' || err.code === 'auth/wrong-password') {
        return 'Credenciales incorrectas. Verifica tu correo y contraseña.';
    }
    if (err.code === 'auth/email-already-in-use') {
        return 'Este correo electrónico ya está registrado.';
    }
    if (err.code === 'auth/popup-closed-by-user') {
        return 'Se cerró la ventana de inicio de sesión antes de terminar.';
    }
    if (err.code === 'auth/popup-blocked') {
        return 'El navegador bloqueó la ventana emergente. Por favor, permítela e intenta de nuevo.';
    }
    return err.message || 'Ocurrió un error inesperado.';
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setLoading(true);

    try {
        let userCredential;
        if (isRegistering) {
            userCredential = await registerWithEmail(email, password, name);
        } else {
            userCredential = await loginWithEmail(email, password);
        }
        // For this demo, we pass the selected role manually since we aren't managing roles in DB yet
        onLogin(userCredential.user, role);
    } catch (err: any) {
        setError(getFriendlyErrorMessage(err));
    } finally {
        setLoading(false);
    }
  };

  const handleGoogleLogin = async () => {
      setError(null);
      setLoading(true); // Show loading state for Google login too
      try {
          const userCredential = await loginWithGoogle();
          onLogin(userCredential.user, role);
      } catch (err: any) {
          setError(getFriendlyErrorMessage(err));
          setLoading(false);
      }
  };

  return (
    <div className="min-h-screen bg-gray-900 flex items-center justify-center p-4">
      <div className="w-full max-w-5xl mx-auto grid md:grid-cols-2 shadow-2xl rounded-lg overflow-hidden">
