            <img 
                src="https://images.pexels.com/photos/3998429/pexels-photo-3998429.jpeg?auto=compress&cs=tinysrgb&w=1260&h=750&dpr=2" 
                alt="Barber applying product to a client's hair" 
                className="w-full h-full object-cover"
            />
            <div className="absolute inset-0 bg-black bg-opacity-60 flex flex-col justify-end p-10 text-white">
                <button onClick={onGoHome} className="text-left focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-black focus:ring-red-500 rounded-lg p-1">
                    <h1 className="text-4xl font-bold tracking-wider">
                        Barber Shop
                        <span className="ml-2 bg-gradient-to-r from-red-500 to-red-600 text-transparent bg-clip-text font-black italic">
                            AI
                        </span>
                    </h1>
                </button>
                <p className="mt-4 text-lg text-gray-300">La herramienta definitiva para la barbería moderna.</p>
            </div>
        </div>

        {/* Right Side: Login Form */}
        <div className="bg-white p-8 md:p-12 flex flex-col justify-center">

            {/* Back Button for Mobile/Desktop */}
            <div className="w-full max-w-md mx-auto mb-6">
                <button
                    onClick={onGoHome}
                    className="flex items-center text-gray-500 hover:text-red-600 transition-colors text-sm font-medium focus:outline-none"
                >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 mr-1" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
                    </svg>
                    Volver al inicio
                </button>
            </div>

            <div className="w-full max-w-md mx-auto">
                 <h2 className="text-3xl font-bold text-gray-800 mb-2">{isRegistering ? 'Crear Cuenta' : 'Bienvenido de Nuevo'}</h2>
                 <p className="text-gray-500 mb-6">Ingresa tus datos para continuar.</p>

                 {/* Role Selector (Simulated for Demo) */}
                 <div className="mb-6 flex bg-gray-100 p-1 rounded-lg">
                    <button 
                        type="button"
                        onClick={() => handleRoleChange('shopOwner')}
                        className={`flex-1 py-2 text-sm font-semibold rounded-md transition-colors ${role === 'shopOwner' ? 'bg-white text-red-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
                    >
                        Dueño de Barbería
                    </button>
                    <button 
                        type="button"
                        onClick={() => handleRoleChange('platformAdmin')}
                        className={`flex-1 py-2 text-sm font-semibold rounded-md transition-colors ${role === 'platformAdmin' ? 'bg-white text-red-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
                    >
                        Admin Plataforma
                    </button>
                 </div>

                <form onSubmit={handleSubmit}>
                    <div className="space-y-4">
                         {isRegistering && (
                            <div>
                                <label htmlFor="name" className="block text-sm font-medium text-gray-700">Nombre Completo</label>
                                <input 
                                    type="text" 
                                    id="name"
                                    value={name}
                                    onChange={(e) => setName(e.target.value)}
                                    required={isRegistering}
                                    className="mt-1 block w-full px-4 py-3 bg-gray-50 border border-gray-300 rounded-md shadow-sm text-gray-900 focus:outline-none focus:ring-red-500 focus:border-red-500"
                                />
                            </div>
                        )}
                        <div>
                            <label htmlFor="email" className="block text-sm font-medium text-gray-700">Correo Electrónico</label>
                            <input 
                                type="email" 
                                id="email"
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                                required
                                className="mt-1 block w-full px-4 py-3 bg-gray-50 border border-gray-300 rounded-md shadow-sm text-gray-900 focus:outline-none focus:ring-red-500 focus:border-red-500"
                            />
                        </div>
                         <div>
                            <label htmlFor="password" className="block text-sm font-medium text-gray-700">Contraseña</label>
                            <input 
                                type="password" 
                                id="password"
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                required
                                className="mt-1 block w-full px-4 py-3 bg-gray-50 border border-gray-300 rounded-md shadow-sm text-gray-900 focus:outline-none focus:ring-red-500 focus:border-red-500"
                            />
                        </div>

                        {error && (
                            <div className="bg-red-50 border-l-4 border-red-500 p-4">
                                <p className="text-red-700 text-sm font-medium">{error}</p>
                            </div>
                        )}

                        <div>
                            <button 
                                type="submit" 
                                disabled={loading}
                                className="w-full flex justify-center py-3 px-4 border border-transparent rounded-md shadow-sm text-lg font-bold text-white bg-red-600 hover:bg-red-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-red-500 transition-transform transform hover:scale-105 disabled:bg-red-400"
                            >
                                {loading ? 'Procesando...' : isRegistering ? 'Registrarse' : 'Ingresar'}
                            </button>
