                    </div>
                </form>

                <div className="my-6 flex items-center">
                    <div className="flex-grow border-t border-gray-300"></div>
                    <span className="flex-shrink mx-4 text-sm text-gray-500">O continúa con</span>
                    <div className="flex-grow border-t border-gray-300"></div>
