export const loginWithEmail = async (email: string, password: string): Promise<{ user: any }> => {
    const userCredential = await signInWithEmailAndPassword(auth, email, password);
    return { user: userCredential.user };
};

export const registerWithEmail = async (email: string, password: string, name: string): Promise<{ user: any }> => {
    const userCredential = await createUserWithEmailAndPassword(auth, email, password);
    // Update the user's display name
    if (userCredential.user) {
        await updateProfile(userCredential.user, {
            displayName: name
        });
        // Create the default shop in Firestore
        await createDefaultShopForUser(userCredential.user.uid, name);
    }
    return { user: userCredential.user };
};

export const loginWithGoogle = async (): Promise<{ user: any }> => {
    const provider = new GoogleAuthProvider();
    const userCredential = await signInWithPopup(auth, provider);

    // Check if shop exists, if not create it (for first time Google logins)
    if (userCredential.user) {
        const shopDoc = await getDoc(doc(db, "shops", userCredential.user.uid));
        if (!shopDoc.exists()) {
             await createDefaultShopForUser(userCredential.user.uid, userCredential.user.displayName || 'Usuario');
        }
    }

    return { user: userCredential.user };
};

