export const loginWithGoogle = async (): Promise<{ user: any }> => {
    const provider = new GoogleAuthProvider();
    const userCredential = await signInWithPopup(auth, provider);

    // Check if shop exists, if not create it (for first time Google logins)
    if (userCredential.user) {
        const shopDoc = await getDoc(doc(db, "shops", userCredential.user.uid));
        if (!shopDoc.exists()) {
             await createDefaultShopForUser(userCredential.user.uid, userCredential.user.displayName || 'Usuario');
        }
    }

    return { user: userCredential.user };
};

