export const getShopForUser = async (userId: string): Promise<BarberShop | null> => {
    const docRef = doc(db, "shops", userId);
    const docSnap = await getDoc(docRef);

    if (docSnap.exists()) {
        return docSnap.data() as BarberShop;
    } else {
        return null;
    }
};

export const updateShopInFirestore = async (shopId: string, data: Partial<BarberShop>) => {
    const docRef = doc(db, "shops", shopId);
    await updateDoc(docRef, data);
};

export const saveBookingToFirestore = async (booking: Omit<Booking, 'id'>) => {
    // Add a timestamp to sort later if needed
    const docRef = await addDoc(collection(db, "bookings"), {
        ...booking,
        createdAt: new Date().toISOString()
    });
    return docRef.id;
};

export const subscribeToUserBookings = (userId: string, callback: (bookings: Booking[]) => void) => {
    const q = query(
        collection(db, "bookings"), 
        where("userId", "==", userId)
    );

    const unsubscribe = onSnapshot(q, (querySnapshot) => {
        const bookings: Booking[] = [];
        querySnapshot.forEach((doc) => {
            bookings.push({ id: doc.id, ...doc.data() } as Booking);
        });
        callback(bookings);
    });

    return unsubscribe;
};

export const subscribeToShopBookings = (shopName: string, callback: (bookings: Booking[]) => void) => {
    const q = query(
        collection(db, "bookings"), 
        where("shopName", "==", shopName)
    );

    const unsubscribe = onSnapshot(q, (querySnapshot) => {
        const bookings: Booking[] = [];
        querySnapshot.forEach((doc) => {
            bookings.push({ id: doc.id, ...doc.data() } as Booking);
        });
        callback(bookings);
    });

    return unsubscribe;
};

