const StripeCheckoutForm: React.FC<{
    onSuccess: (method: PaymentMethod) => void, 
    onError: (err: string) => void 
}> = ({ onSuccess, onError }) => {
    const stripe = useStripe();
    const elements = useElements();
    const [isLoading, setIsLoading] = useState(false);

    const handleSubmit = async (event: React.FormEvent) => {
        event.preventDefault();

        if (!stripe || !elements) return;

        setIsLoading(true);

        const result = await stripe.confirmPayment({
            elements,
            confirmParams: {
                return_url: window.location.href, // This handles 3D Secure redirects
            },
            redirect: "if_required", // Don't redirect if not needed
        });

        if (result.error) {
            onError(result.error.message || "Payment failed");
            setIsLoading(false);
        } else if (result.paymentIntent && result.paymentIntent.status === "succeeded") {
            // Success!
            onSuccess({
                type: 'Visa', // We simplify here, real data comes from paymentIntent details if needed
                last4: '****', 
                expiry: '**/**'
            });
        }
    };

    return (
        <form onSubmit={handleSubmit} className="space-y-4 mt-4">
            <PaymentElement />
            <button 
                type="submit" 
                disabled={!stripe || isLoading} 
                className="w-full mt-4 bg-red-600 text-white font-bold py-3 rounded-lg hover:bg-red-700 transition-colors disabled:bg-gray-300"
            >
                {isLoading ? 'Procesando...' : 'Pagar y Suscribirse'}
            </button>
        </form>
    );
}

