                                    <span className="block sm:inline text-sm">{errorMessage}</span>
                                </div>
                            )}

                            {/* Stripe Content */}
                            {activeProvider === 'card' && (
                                <>
                                    {clientSecret && stripePromise ? (
                                        <Elements stripe={stripePromise} options={{ clientSecret, appearance: { theme: 'stripe' } }}>
                                            <StripeCheckoutForm 
