                setCurrentUser(null);
                setShops(barbershops); // Reset to mock data on logout
                setScreen('home');
            }
            setIsInitializing(false); // Done checking
        });
    } else {
        setIsInitializing(false);
    }

    return () => unsubscribe();
  }, []);

  // --- Realtime Bookings Listener ---
  useEffect(() => {
      if (currentUser && firebaseUser && !isInitializing) {
          let unsubscribe: () => void;

          if (currentUser.role === 'shopOwner' && currentShop) {
              // If owner, listen to all bookings for their shop
              unsubscribe = subscribeToShopBookings(currentShop.name, (fetchedBookings) => {
                  setBookings(fetchedBookings);
              });
          } else {
              // If user/admin/other, listen to their own bookings
              unsubscribe = subscribeToUserBookings(firebaseUser.uid, (fetchedBookings) => {
                  setBookings(fetchedBookings);
              });
          }

          return () => {
              if (unsubscribe) unsubscribe();
          };
      }
  }, [currentUser, firebaseUser, currentShop, isInitializing]);


  const handleShowLogin = () => setScreen('login');

  const handleLogin = (user: any, role: 'platformAdmin' | 'shopOwner') => {
    localStorage.setItem('userRole', role);
    // State update happens in onAuthStateChanged
    // Setting screen to app immediately can cause flickering if fetch hasn't finished,
    // so we rely on the listener to flip the screen switch.
    setIsInitializing(true); 
  };

  const handleLogout = async () => {
    setIsInitializing(true);
    await logoutUser();
    localStorage.removeItem('userRole');
    setCurrentUser(null);
    setFirebaseUser(null);
    setScreen('home');
    setIsInitializing(false);
  };

  const handleGoHome = () => {
    setScreen('home');
  };

  const handleAddBooking = (bookingDetails: Omit<Booking, 'id'>) => {
      // Listener handles updates
  };

  const handleUploadNew = () => {
      setAppState('initial');
      setFrontUserImage(null);
      setSideUserImage(null);
      setSuggestedStyles([]);
      setAnalysisResult(null);
      setGeneratedImages(Array(12).fill(null));
      setOriginalGeneratedImages(Array(12).fill(null));
      setIsGeneratingImages(Array(12).fill(false));
      setActiveAngle('front');
      setActiveLighting('Natural');
  };

  const initializeAndReset = useCallback((shop: BarberShop) => {
    handleUploadNew();
    try {
      chatSession.current = initChatSession(shop);
      setMessages([
        {
          id: 'init',
          sender: 'ai',
          text: shop.welcomeMessage,
        },
      ]);
    } catch (error) {
      console.error("Failed to initialize chat session:", error);
      setMessages([{
        id: 'error-init',
        sender: 'ai',
        text: 'Lo siento, no puedo conectarme en este momento. Asegúrate de que el servidor Backend esté funcionando.',
      }]);
    }
  }, []);

  useEffect(() => {
    if (currentShop) {
      initializeAndReset(currentShop);
    } else {
      setMessages([]);
      chatSession.current = null;
    }
  }, [currentShop, initializeAndReset]);

  const handlePhotosReady = async (frontFile: File, sideFile: File) => {
    if (!currentShop) return;
    setAppState('processing');
    setIsAiLoading(true);

    const [frontImg, sideImg] = await Promise.all([
        fileToDataUrl(frontFile),
        fileToDataUrl(sideFile)
    ]);

    setFrontUserImage({data: frontImg.data, mimeType: frontImg.mimeType, url: frontImg.dataUrl});
    setSideUserImage({data: sideImg.data, mimeType: sideImg.mimeType, url: sideImg.dataUrl});

    const frontImagePart = { inlineData: { mimeType: frontImg.mimeType, data: frontImg.data } };
    const sideImagePart = { inlineData: { mimeType: sideImg.mimeType, data: sideImg.data } };

    try {
        const { styles, finalRecommendation } = await getStyleRecommendations(frontImagePart, sideImagePart, currentShop);

        setAnalysisResult(finalRecommendation);
        setSuggestedStyles(styles);
        setAppState('results');
        setActiveView('mirror'); 
        visualizeStyles(
            styles,
            { data: frontImg.data, mimeType: frontImg.mimeType },
            { data: sideImg.data, mimeType: sideImg.mimeType },
            'Natural'
        );

    } catch (error) {
      console.error('Error getting style recommendations:', error);
      setMessages((prev) => [...prev, {
        id: 'error-style-rec',
        sender: 'ai',
        text: '¡Vaya! Algo salió mal al analizar tus fotos. Por favor, asegúrate de que las imágenes sean nítidas y vuelve a intentarlo.',
      }]);
      handleUploadNew();
      setActiveView('chat');
    } finally {
      setIsAiLoading(false);
    }
  };

  const visualizeStyles = (
    styles: string[],
    frontImage: { data: string; mimeType: string },
    sideImage: { data: string; mimeType: string },
    lighting: string
    ) => {
    if (styles.length < 4) {
        console.warn("Not enough styles provided to visualize, padding with generic.");
        while(styles.length < 4) styles.push("Estilo por IA");
    }

    const imagesToGenerate: { image: any, style: string, angle: 'Frente' | 'Perfil' | 'Tres Cuartos', index: number }[] = [];

    styles.forEach((style, i) => {
        imagesToGenerate.push({ image: frontImage, style: style, angle: 'Frente', index: i });
        imagesToGenerate.push({ image: sideImage, style: style, angle: 'Perfil', index: i + 4 });
    });

    const generateSequentially = async () => {
        for (const { image, style, angle, index } of imagesToGenerate) {
             setIsGeneratingImages(prev => { const next = [...prev]; next[index] = true; return next; });
             try {
                 await new Promise(r => setTimeout(r, 400));
                 const generatedImageUrl = await generateStyledImage(image.data, image.mimeType, style, angle, lighting);
                 setGeneratedImages(prev => { const next = [...prev]; next[index] = generatedImageUrl; return next; });
                 setOriginalGeneratedImages(prev => { const next = [...prev]; next[index] = generatedImageUrl; return next; });
             } catch (error) {
                 console.error(`Error generating image for style "${style}" (index ${index}):`, error);
             } finally {
                 setIsGeneratingImages(prev => { const next = [...prev]; next[index] = false; return next; });
             }
        }
    };

    generateSequentially();
  };

  const handleRegenerateSingleImage = async (index: number) => {
    if (isGeneratingImages[index] || !suggestedStyles.length) return;

    let angle: 'Frente' | 'Perfil' | 'Tres Cuartos' = 'Frente';
    let sourceImage = frontUserImage;
    const styleIndex = index % 4;
    const style = suggestedStyles[styleIndex];

    if (index >= 4 && index < 8) {
        angle = 'Perfil';
        sourceImage = sideUserImage;
    } else if (index >= 8) {
        angle = 'Tres Cuartos';
        sourceImage = frontUserImage; 
    }

    if (!sourceImage) return;

    setIsGeneratingImages(prev => { const next = [...prev]; next[index] = true; return next; });
    try {
        const generatedImageUrl = await generateStyledImage(sourceImage.data, sourceImage.mimeType, style, angle, activeLighting);
        setGeneratedImages(prev => { const next = [...prev]; next[index] = generatedImageUrl; return next; });
        setOriginalGeneratedImages(prev => { const next = [...prev]; next[index] = generatedImageUrl; return next; });
    } catch (error) {
        console.error(`Error regenerating image at index ${index}:`, error);
    } finally {
        setIsGeneratingImages(prev => { const next = [...prev]; next[index] = false; return next; });
    }
  };

  const handleAngleChange = (angle: 'front' | 'side' | 'threeQuarter') => {
      setActiveAngle(angle);
      const startIdx = 8;
      const needsGeneration = suggestedStyles.some((_, i) => !originalGeneratedImages[startIdx + i] && !isGeneratingImages[startIdx + i]);

      if (angle === 'threeQuarter' && needsGeneration && frontUserImage && sideUserImage) {
          const styles = suggestedStyles;
          const imagesToGenerate: { image: any, style: string, angle: 'Tres Cuartos', index: number }[] = [];

          styles.forEach((style, i) => {
             imagesToGenerate.push({ image: frontUserImage, style: style, angle: 'Tres Cuartos', index: startIdx + i });
          });

          const generateSequentially = async () => {
             for(const { image, style, angle, index } of imagesToGenerate) {
                  setIsGeneratingImages(prev => { const next = [...prev]; next[index] = true; return next; });
                  try {
                      await new Promise(r => setTimeout(r, 300));
                      const generatedImageUrl = await generateStyledImage(image.data, image.mimeType, style, angle, activeLighting);
                      setGeneratedImages(prev => { const next = [...prev]; next[index] = generatedImageUrl; return next; });
                      setOriginalGeneratedImages(prev => { const next = [...prev]; next[index] = generatedImageUrl; return next; });
                  } catch (error) {
                      console.error(`Error generating image for style "${style}" (index ${index}):`, error);
                  } finally {
                      setIsGeneratingImages(prev => { const next = [...prev]; next[index] = false; return next; });
                  }
             }
          }
          generateSequentially();
      }
  };

  const handleLightingChange = (lighting: string) => {
      setActiveLighting(lighting);
      setGeneratedImages(Array(12).fill(null));
      setOriginalGeneratedImages(Array(12).fill(null));
      if (frontUserImage && sideUserImage && suggestedStyles.length > 0) {
          visualizeStyles(suggestedStyles, frontUserImage, sideUserImage, lighting);
          if (activeAngle === 'threeQuarter') {
               setTimeout(() => handleAngleChange('threeQuarter'), 4000); 
          }
      }
  };

  const processImageModification = async (
    modificationFn: (data: string, mimeType: string, param: string) => Promise<string>,
    param: string,
    sourceImages: (string | null)[]
  ) => {
    for (let i = 0; i < sourceImages.length; i++) {
        const imageUrl = sourceImages[i];
        if (!imageUrl) continue;

        setIsGeneratingImages(prev => { const next = [...prev]; next[i] = true; return next; });
        try {
              await new Promise(r => setTimeout(r, 200));
              const response = await fetch(imageUrl);
              const blob = await response.blob();
              const { data, mimeType } = await fileToDataUrl(new File([blob], `source.png`, { type: blob.type }));
              const modifiedImageUrl = await modificationFn(data, mimeType, param);
              setGeneratedImages(prev => { const next = [...prev]; next[i] = modifiedImageUrl; return next; });
          } catch (error) {
              console.error(`Error modifying image index ${i} with param ${param}:`, error);
          } finally {
              setIsGeneratingImages(prev => { const next = [...prev]; next[i] = false; return next; });
          }
    }
  };

  const handleColorChange = async (color: string) => {
    if (color === 'Natural') {
        setGeneratedImages(originalGeneratedImages);
        return;
    }
    await processImageModification(applyHairColor, color, originalGeneratedImages);
  };

  const handleHighlightsChange = async (color: string) => {
    if (color === 'None') {
        setGeneratedImages(originalGeneratedImages);
        return;
    }
    await processImageModification(applyHairHighlights, color, generatedImages);
  };

  const handleShare = async () => {
    if (!currentShop) return;
    const imagesToShareUrls = [];

    let offset = 0;
    if (activeAngle === 'side') offset = 4;
    if (activeAngle === 'threeQuarter') offset = 8;

    for(let i=0; i<4; i++) {
        const idx = offset + i;
        if (generatedImages[idx] && suggestedStyles[i]) {
            imagesToShareUrls.push({ url: generatedImages[idx]!, name: suggestedStyles[i] });
        }
    }

    if (imagesToShareUrls.length === 0) {
        alert("No hay imágenes generadas para compartir.");
        return;
    }

    try {
        const files = await Promise.all(
            imagesToShareUrls.map(({url, name}) => 
                dataUrlToFile(url, `${name.replace(/\s+/g, '-')}-${activeAngle}.png`)
            )
        );

        if (navigator.canShare && navigator.canShare({ files })) {
            await navigator.share({
                title: 'Mi Nuevo Look de Barber Shop AI',
                text: `¡Mira estos nuevos estilos de cabello que ${currentShop.aiName} de ${currentShop.name} me sugirió!`,
                files: files,
            });
        } else {
             alert('Tu navegador no soporta compartir archivos. Inténtalo desde un dispositivo móvil.');
        }
    } catch (error) {
        console.error('Error sharing:', error);
        alert('Hubo un error al intentar compartir. Es posible que hayas cancelado la acción.');
    }
  };

  const handleSendMessage = async (userInput: string) => {
    if (!userInput.trim() || isAiLoading) return;

    const newUserMessage: Message = {
      id: Date.now().toString(),
      sender: 'user',
      text: userInput
    };
    setMessages((prevMessages) => [...prevMessages, newUserMessage]);
    setIsAiLoading(true);

    try {
      if (!chatSession.current) throw new Error("Chat session not initialized.");
      const stream = await chatSession.current.sendMessageStream({ message: userInput });
      let aiMessageId: string | null = null;
      let accumulatedText = "";
      for await (const chunk of stream) {
        accumulatedText += chunk.text;
        if (!aiMessageId) {
          aiMessageId = (Date.now() + 1).toString();
          setMessages((prev) => [...prev, { id: aiMessageId!, sender: 'ai', text: accumulatedText }]);
        } else {
          setMessages((prev) => prev.map((msg) => msg.id === aiMessageId ? { ...msg, text: accumulatedText } : msg));
        }
      }
    } catch (error) {
      console.error('Error sending message:', error);
      setMessages((prev) => [...prev, {
        id: 'error-send',
        sender: 'ai',
        text: '¡Ups! Algo salió mal. Por favor, intenta de nuevo.',
      }]);
    } finally {
      setIsAiLoading(false);
    }
  };

  const handleResetChat = () => {
    if(chatSession.current && currentShop) {
        initializeAndReset(currentShop);
    }
  };

  const handleOpenModal = (url: string, caption: string) => setModalImage({ url, caption });
  const handleCloseModal = () => setModalImage(null);

  const handleNavigate = (view: ActiveView) => {
      if (view === 'mirror' && appState === 'initial') {
        handleUploadNew();
      }
      setActiveView(view);
      setIsSidebarOpen(false);
  }

  const handleUpdateShopProfile = async (updatedShop: BarberShop) => {
    // Optimistic Update
    setShops(prevShops => prevShops.map(shop => shop.id === updatedShop.id ? updatedShop : shop));

    // Save to Firestore if it's the current user's shop
    if (currentUser?.shopId === updatedShop.id) {
        try {
            await updateShopInFirestore(updatedShop.id, updatedShop);
        } catch (e) {
            console.error("Failed to save shop profile", e);
            alert("Error al guardar en la base de datos.");
        }
    }
  };

  const handleUpdatePlan = async (shopId: string, newPlan: 'Freemium' | 'Básico' | 'Profesional') => {
    setShops(prevShops => prevShops.map(shop => shop.id === shopId ? { ...shop, plan: newPlan } : shop));
    if (currentUser?.shopId === shopId) {
        await updateShopInFirestore(shopId, { plan: newPlan });
    }
  };

  const handleUpdatePaymentMethod = async (shopId: string, newMethod: PaymentMethod) => {
     setShops(prevShops => prevShops.map(shop => shop.id === shopId ? { ...shop, paymentMethod: newMethod } : shop));
     if (currentUser?.shopId === shopId) {
        await updateShopInFirestore(shopId, { paymentMethod: newMethod });
    }
  };

  const viewTitles: { [key in ActiveView]: string } = {
    chat: 'Chat de Estilismo',
    mirror: 'Espejo Virtual',
    booking: 'Reservar Cita',
    bookingsList: 'Mis Reservas',
    shopProfile: 'Perfil de la Barbería',
    billing: 'Facturación y Plan',
    admin: 'Dashboard de Barbería',
    platformAdmin: 'Dashboard de Plataforma'
  };

  if (isInitializing) {
     return (
        <div className="flex h-screen w-full items-center justify-center bg-gray-100 flex-col gap-4">
             <div className="w-16 h-16 border-4 border-red-500 border-t-transparent rounded-full animate-spin"></div>
             <p className="text-gray-600 font-medium">Conectando con Barber Shop AI...</p>
        </div>
     );
  }

  if (screen === 'home') {
    return <HomeView onShowLogin={handleShowLogin} onGoHome={handleGoHome} />;
  }
  if (screen === 'login') {
    return <LoginView onLogin={handleLogin} onGoHome={handleGoHome} />;
  }

  return (
    <PayPalScriptProvider options={paypalOptions}>
    <div className="relative flex h-screen bg-gray-100 text-gray-800 font-sans overflow-hidden">
      {modalImage && <ImageModal imageUrl={modalImage.url} caption={modalImage.caption} onClose={handleCloseModal} />}

      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-30 lg:hidden"
          onClick={() => setIsSidebarOpen(false)}
          aria-hidden="true"
        ></div>
      )}

      <Sidebar 
        currentUser={currentUser}
        currentShop={currentShop}
        onResetChat={handleResetChat}
        activeView={activeView}
        onNavigate={handleNavigate}
        isOpen={isSidebarOpen}
        setIsOpen={setIsSidebarOpen}
        onLogout={handleLogout}
        onGoHome={handleGoHome}
      />

      <div className="flex-1 flex flex-col overflow-hidden">
         <MainHeader 
            title={viewTitles[activeView]} 
            onMenuClick={() => setIsSidebarOpen(true)}
        />
        <main className="flex-1 overflow-y-auto">
            {currentUser?.role === 'platformAdmin' && activeView === 'platformAdmin' && (
              <PlatformAdminView shops={shops} bookings={bookings} />
            )}
            {currentUser?.role === 'shopOwner' && currentShop && (
                <>
                    {activeView === 'chat' && (
                      <ChatView 
                        messages={messages}
                        isAiLoading={isAiLoading}
                        onSendMessage={handleSendMessage}
                        appState={appState}
                      />
                    )}
                    {activeView === 'mirror' && (
                      <MirrorView 
                        appState={appState}
                        isAiLoading={isAiLoading}
                        onPhotosReady={handlePhotosReady}
                        currentShopName={currentShop.name}
                        aiName={currentShop.aiName}
                        frontUserImageUrl={frontUserImage?.url ?? null}
                        sideUserImageUrl={sideUserImage?.url ?? null}
                        generatedImages={generatedImages}
                        suggestedStyles={suggestedStyles}
                        analysisResult={analysisResult}
                        isGeneratingImages={isGeneratingImages}
                        activeAngle={activeAngle}
                        onAngleChange={handleAngleChange}
                        onLightingChange={handleLightingChange}
                        onColorChange={handleColorChange}
                        onHighlightsChange={handleHighlightsChange}
                        onRegenerateImage={handleRegenerateSingleImage}
                        onShare={handleShare}
                        onUploadNew={handleUploadNew}
                        onImageClick={handleOpenModal}
                      />
                    )}
                    {activeView === 'booking' && (
                      <BookingView 
                        shop={currentShop} 
                        onBookingConfirmed={handleAddBooking} 
                        userId={firebaseUser?.uid || 'anon'}
                        userEmail={firebaseUser?.email || ''} // Pass the email here
                      />
                    )}
                    {activeView === 'bookingsList' && (
                        <BookingsListView bookings={bookings} onNavigate={handleNavigate} />
                    )}
                    {activeView === 'shopProfile' && (
                        <ShopProfileView shop={currentShop} onUpdateProfile={handleUpdateShopProfile} />
                    )}
                    {activeView === 'billing' && (
                        <BillingView 
                          shop={currentShop} 
                          onUpdatePlan={handleUpdatePlan} 
                          onUpdatePaymentMethod={handleUpdatePaymentMethod} 
                        />
                    )}
                    {activeView === 'admin' && (
                        <AdminView currentShop={currentShop} bookings={bookings} />
                    )}
                </>
            )}
        </main>
      </div>
    </div>
    </PayPalScriptProvider>
  );
};

