export const createDefaultShopForUser = async (userId: string, userName: string) => {
    const defaultShop: BarberShop = {
        id: userId, // Use UID as Shop ID for 1:1 simplicity
        ownerId: userId,
        name: `${userName || 'Mi'} Barber Shop`,
        aiName: 'Barbero AI',
        welcomeMessage: '¡Hola! Bienvenido. Soy tu asistente virtual. Sube tus fotos para empezar.',
        aiPersona: 'Eres un barbero profesional y amable. Te gusta el estilo moderno.',
        description: 'Una barbería moderna enfocada en el estilo y la tecnología.',
        address: 'Dirección por configurar',
        phone: '(000) 000-0000',
        hours: {
            'Lunes-Viernes': '09:00 - 18:00',
            'Sábado': '10:00 - 14:00'
        },
        gallery: [],
        services: [
            { name: 'Corte de Cabello', price: '$20' }
        ],
        barbers: [
            { name: userName || 'Dueño', specialty: 'General', imageUrl: 'https://via.placeholder.com/150' }
        ],
        plan: 'Freemium',
        billingHistory: [],
        paymentMethod: {
            type: 'Visa',
            last4: '0000',
            expiry: '00/00'
        }
    };

    await setDoc(doc(db, "shops", userId), defaultShop);
    return defaultShop;
};

export const loginWithEmail = async (email: string, password: string): Promise<{ user: any }> => {
    const userCredential = await signInWithEmailAndPassword(auth, email, password);
    return { user: userCredential.user };
};

export const registerWithEmail = async (email: string, password: string, name: string): Promise<{ user: any }> => {
    const userCredential = await createUserWithEmailAndPassword(auth, email, password);
    // Update the user's display name
    if (userCredential.user) {
        await updateProfile(userCredential.user, {
            displayName: name
        });
        // Create the default shop in Firestore
        await createDefaultShopForUser(userCredential.user.uid, name);
    }
    return { user: userCredential.user };
};

export const loginWithGoogle = async (): Promise<{ user: any }> => {
    const provider = new GoogleAuthProvider();
    const userCredential = await signInWithPopup(auth, provider);

    // Check if shop exists, if not create it (for first time Google logins)
    if (userCredential.user) {
        const shopDoc = await getDoc(doc(db, "shops", userCredential.user.uid));
        if (!shopDoc.exists()) {
             await createDefaultShopForUser(userCredential.user.uid, userCredential.user.displayName || 'Usuario');
        }
    }

    return { user: userCredential.user };
};

export const logoutUser = async () => {
    await signOut(auth);
};

// --- Firestore Data Services (MODULAR) ---

export const getShopForUser = async (userId: string): Promise<BarberShop | null> => {
    const docRef = doc(db, "shops", userId);
    const docSnap = await getDoc(docRef);

    if (docSnap.exists()) {
        return docSnap.data() as BarberShop;
    } else {
        return null;
    }
};

export const updateShopInFirestore = async (shopId: string, data: Partial<BarberShop>) => {
    const docRef = doc(db, "shops", shopId);
    await updateDoc(docRef, data);
};

export const saveBookingToFirestore = async (booking: Omit<Booking, 'id'>) => {
    // Add a timestamp to sort later if needed
    const docRef = await addDoc(collection(db, "bookings"), {
        ...booking,
        createdAt: new Date().toISOString()
    });
    return docRef.id;
};

export const subscribeToUserBookings = (userId: string, callback: (bookings: Booking[]) => void) => {
    const q = query(
        collection(db, "bookings"), 
        where("userId", "==", userId)
    );

    const unsubscribe = onSnapshot(q, (querySnapshot) => {
        const bookings: Booking[] = [];
        querySnapshot.forEach((doc) => {
            bookings.push({ id: doc.id, ...doc.data() } as Booking);
        });
        callback(bookings);
    });

    return unsubscribe;
};

export const subscribeToShopBookings = (shopName: string, callback: (bookings: Booking[]) => void) => {
    const q = query(
        collection(db, "bookings"), 
        where("shopName", "==", shopName)
    );

    const unsubscribe = onSnapshot(q, (querySnapshot) => {
        const bookings: Booking[] = [];
        querySnapshot.forEach((doc) => {
            bookings.push({ id: doc.id, ...doc.data() } as Booking);
        });
        callback(bookings);
    });

    return unsubscribe;
};

// --- Storage Services ---

export const uploadShopImage = async (file: File, shopId: string, folder: 'gallery' | 'barbers'): Promise<string> => {
    if (!file) throw new Error("No se proporcionó ningún archivo.");

    // 1. Validation
    if (!file.type.startsWith('image/')) {
        throw new Error("El archivo debe ser una imagen válida (JPG, PNG, etc).");
    }

    const MAX_SIZE = 5 * 1024 * 1024; // 5MB
    if (file.size > MAX_SIZE) {
        throw new Error("La imagen es demasiado grande. El tamaño máximo es 5MB.");
    }

    // Sanitize filename: replace spaces and special chars with underscores to avoid path issues
    const sanitizedFileName = file.name.replace(/[^a-zA-Z0-9.]/g, '_');
    const filename = `${Date.now()}_${sanitizedFileName}`;
    const storagePath = `shops/${shopId}/${folder}/${filename}`;
    const storageRef = ref(storage, storagePath);

    // Add metadata so Firebase knows it's an image
    const metadata = {
        contentType: file.type,
    };

    try {
        console.log(`[Storage] Iniciando carga de: ${file.name} a ${storagePath}`);
        const snapshot = await uploadBytes(storageRef, file, metadata);
        console.log(`[Storage] Carga completada. Bytes transferidos: ${snapshot.bytesTransferred}`);

        const downloadURL = await getDownloadURL(storageRef);
        console.log(`[Storage] URL de descarga obtenida: ${downloadURL}`);

        return downloadURL;
    } catch (error: any) {
        console.error("[Storage] Error en subida:", error);

        // Friendly error mapping for verification/debugging
        if (error.code === 'storage/unauthorized') {
            throw new Error("Permiso denegado: No tienes autorización para subir archivos. Verifica tus Reglas de Seguridad en Firebase.");
        } else if (error.code === 'storage/retry-limit-exceeded') {
             throw new Error("La subida falló porque se excedió el límite de tiempo. Verifica tu conexión.");
        } else if (error.code === 'storage/quota-exceeded') {
             throw new Error("Has excedido tu cuota de almacenamiento de Firebase.");
        } else if (error.code === 'storage/object-not-found') {
            throw new Error("El archivo no se pudo encontrar después de subirlo.");
        }

        throw error;
    }
};

import React, { useState, useEffect, useRef } from 'react';
import { BarberShop, Service, Barber } from '../types';
import { EditIcon } from '../assets/icons';
import { uploadShopImage } from '../services/firebaseService';

interface ShopProfileViewProps {
  shop: BarberShop;
  onUpdateProfile: (updatedShop: BarberShop) => void;
}

const ShopProfileView: React.FC<ShopProfileViewProps> = ({ shop, onUpdateProfile }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [editableShop, setEditableShop] = useState<BarberShop>(shop);
  const [isUploading, setIsUploading] = useState(false);

  const [newService, setNewService] = useState({ name: '', price: '' });
  const [newBarber, setNewBarber] = useState({ name: '', specialty: '', imageUrl: '' });

  // Refs for file inputs
  const galleryInputRef = useRef<HTMLInputElement>(null);
  const barberInputRef = useRef<HTMLInputElement>(null);
  const editBarberInputRefs = useRef<(HTMLInputElement | null)[]>([]);

  const inputClasses = "w-full bg-gray-50 border border-gray-300 rounded-md p-2 text-gray-800 focus:ring-2 focus:ring-red-500 focus:border-transparent transition-shadow shadow-sm";
  const smallInputClasses = "w-full bg-transparent border-b border-gray-300 py-1 text-gray-800 focus:outline-none focus:border-red-500";
  const removeButtonClasses = "absolute top-2 right-2 bg-red-600 text-white rounded-full w-6 h-6 flex items-center justify-center text-sm font-bold shadow-md hover:bg-red-700 transition-transform hover:scale-110 z-10";
  const addButtonClasses = "bg-blue-600 text-white font-semibold px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors text-sm shadow-sm disabled:bg-blue-300 disabled:cursor-not-allowed";

  useEffect(() => {
    setEditableShop(shop);
    setIsEditing(false);
  }, [shop]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setEditableShop(prev => ({ ...prev, [name]: value }));
  };

  const handleNestedChange = <T,>(section: keyof BarberShop, index: number, field: keyof T, value: string) => {
    const newSection = [...(editableShop[section] as T[])];
    newSection[index] = { ...newSection[index], [field]: value };
    setEditableShop(prev => ({ ...prev, [section]: newSection }));
  };

  const handleAddItem = (section: keyof BarberShop) => {
    let newItem: any;
    // Gallery uses direct upload logic now, handled by handleGalleryUpload
    if (section === 'services') {
      if (!newService.name.trim() || !newService.price.trim()) return;
      newItem = newService;
      const currentItems = editableShop[section] as any[];
      setEditableShop(prev => ({ ...prev, [section]: [...currentItems, newItem] }));
      setNewService({ name: '', price: '' });
    } else if (section === 'barbers') {
       // Barbers logic handles text fields, image is handled via state before adding
       if (!newBarber.name.trim() || !newBarber.specialty.trim() || !newBarber.imageUrl.trim()) {
           alert("Por favor completa nombre, especialidad y sube una foto.");
           return;
       }
       newItem = newBarber;
       const currentItems = editableShop[section] as any[];
       setEditableShop(prev => ({ ...prev, [section]: [...currentItems, newItem] }));
       setNewBarber({ name: '', specialty: '', imageUrl: '' });
    }
  };

  const handleRemoveItem = (section: keyof BarberShop, index: number) => {
    const newSection = (editableShop[section] as any[]).filter((_, i) => i !== index);
    setEditableShop(prev => ({ ...prev, [section]: newSection }));
  };

  const handleHourChange = (day: string, value: string) => {
    setEditableShop(prev => ({
        ...prev,
        hours: { ...prev.hours, [day]: value }
    }));
  };

  // --- Upload Logic ---

  const handleGalleryUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      setIsUploading(true);
      try {
          const url = await uploadShopImage(file, shop.id, 'gallery');
          setEditableShop(prev => ({ ...prev, gallery: [...prev.gallery, url] }));
      } catch (error: any) {
          console.error("Upload failed", error);
          alert(error.message || "Error desconocido al subir imagen.");
      } finally {
          setIsUploading(false);
          // Reset input
          if (galleryInputRef.current) galleryInputRef.current.value = "";
      }
  };

  const handleNewBarberImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      setIsUploading(true);
      try {
          const url = await uploadShopImage(file, shop.id, 'barbers');
          setNewBarber(prev => ({ ...prev, imageUrl: url }));
      } catch (error: any) {
          console.error("Upload failed", error);
          alert(error.message || "Error desconocido al subir imagen.");
      } finally {
          setIsUploading(false);
          if (barberInputRef.current) barberInputRef.current.value = "";
      }
  };

  const handleEditBarberImageUpload = async (e: React.ChangeEvent<HTMLInputElement>, index: number) => {
      const file = e.target.files?.[0];
      if (!file) return;

