           console.error("Upload failed", error);
           alert(error.message || "Error desconocido al subir imagen.");
      } finally {
          setIsUploading(false);
          if (editBarberInputRefs.current[index]) {
              editBarberInputRefs.current[index]!.value = "";
          }
      }
  };


  const handleSave = () => {
    onUpdateProfile(editableShop);
    setIsEditing(false);
  };

