          ) : (
            <h1 className="text-4xl lg:text-5xl font-extrabold text-gray-900 tracking-tight">{shop.name}</h1>
          )}
          {isEditing ? (
             <input type="text" name="address" value={editableShop.address} onChange={handleInputChange} className={`text-lg text-center ${inputClasses}`} />
          ) : (
            <p className="mt-2 text-lg text-gray-500">{shop.address}</p>
          )}

          <div className="absolute top-0 right-0 flex gap-2">
            {isEditing ? (
                <>
                    <button onClick={handleSave} disabled={isUploading} className="bg-green-600 text-white font-semibold px-4 py-2 rounded-lg hover:bg-green-700 transition-colors text-sm disabled:bg-gray-400">
                        {isUploading ? 'Subiendo...' : 'Guardar'}
                    </button>
                    <button onClick={handleCancel} disabled={isUploading} className="bg-gray-500 text-white font-semibold px-4 py-2 rounded-lg hover:bg-gray-600 transition-colors text-sm disabled:bg-gray-400">Cancelar</button>
                </>
            ) : (
                <button onClick={() => setIsEditing(true)} className="bg-red-600 text-white font-semibold px-4 py-2 rounded-lg hover:bg-red-700 transition-colors flex items-center gap-2">
                    <EditIcon className="w-5 h-5" />
                    <span>Editar Perfil</span>
                </button>
            )}
          </div>
        </header>

        <main className="grid grid-cols-1 lg:grid-cols-3 gap-8 lg:gap-12">
          {/* Main Content: About, Gallery, Services */}
          <div className="lg:col-span-2 space-y-10">
