                {isEditing && (
                    <div className="flex gap-2 pt-4 border-t border-gray-200">
                        <input type="text" placeholder="Nombre del servicio" value={newService.name} onChange={e => setNewService(s => ({...s, name: e.target.value}))} className={`flex-grow ${inputClasses}`}/>
                        <input type="text" placeholder="Precio" value={newService.price} onChange={e => setNewService(s => ({...s, price: e.target.value}))} className={`w-28 ${inputClasses}`}/>
