  const orderDescription = isChangingPlan && newPlan 
      ? `Suscripcion ${newPlan} - Barber Shop AI` 
      : 'Actualizacion Metodo de Pago - Barber Shop AI';

  // Reset state on open
  useEffect(() => {
    if (isOpen) {
        setClientSecret(null);
        setErrorMessage(null);
        setIsSuccess(false);
        setActiveProvider('card');
    }
  }, [isOpen]);

  // Fetch Payment Intent for Stripe
  useEffect(() => {
    if (isOpen && activeProvider === 'card' && STRIPE_PUBLISHABLE_KEY && !isFree) {
        fetch(`${API_BASE_URL}/create-payment-intent`, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ 
                amount: priceNum, 
