import React, { useState, useEffect, useRef } from 'react';
import { BarberShop, Service, Barber } from '../types';
import { EditIcon } from '../assets/icons';
import { uploadShopImage } from '../services/firebaseService';

interface ShopProfileViewProps {
  shop: BarberShop;
  onUpdateProfile: (updatedShop: BarberShop) => void;
}

const ShopProfileView: React.FC<ShopProfileViewProps> = ({ shop, onUpdateProfile }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [editableShop, setEditableShop] = useState<BarberShop>(shop);
  const [isUploading, setIsUploading] = useState(false);
  const [uploadSuccess, setUploadSuccess] = useState<string | null>(null); // New state for success feedback

  const [newService, setNewService] = useState({ name: '', price: '' });
  const [newBarber, setNewBarber] = useState({ name: '', specialty: '', imageUrl: '' });

  // Refs for file inputs
  const galleryInputRef = useRef<HTMLInputElement>(null);
  const barberInputRef = useRef<HTMLInputElement>(null);
  const editBarberInputRefs = useRef<(HTMLInputElement | null)[]>([]);

  const inputClasses = "w-full bg-gray-50 border border-gray-300 rounded-md p-2 text-gray-800 focus:ring-2 focus:ring-red-500 focus:border-transparent transition-shadow shadow-sm";
  const smallInputClasses = "w-full bg-transparent border-b border-gray-300 py-1 text-gray-800 focus:outline-none focus:border-red-500";
  const removeButtonClasses = "absolute top-2 right-2 bg-red-600 text-white rounded-full w-6 h-6 flex items-center justify-center text-sm font-bold shadow-md hover:bg-red-700 transition-transform hover:scale-110 z-10";
  const addButtonClasses = "bg-blue-600 text-white font-semibold px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors text-sm shadow-sm disabled:bg-blue-300 disabled:cursor-not-allowed";

  useEffect(() => {
    setEditableShop(shop);
    setIsEditing(false);
  }, [shop]);

  // Clear success message after 3 seconds
  useEffect(() => {
      if (uploadSuccess) {
          const timer = setTimeout(() => setUploadSuccess(null), 3000);
          return () => clearTimeout(timer);
      }
  }, [uploadSuccess]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setEditableShop(prev => ({ ...prev, [name]: value }));
  };

  const handleNestedChange = <T,>(section: keyof BarberShop, index: number, field: keyof T, value: string) => {
    const newSection = [...(editableShop[section] as T[])];
    newSection[index] = { ...newSection[index], [field]: value };
    setEditableShop(prev => ({ ...prev, [section]: newSection }));
  };

  const handleAddItem = (section: keyof BarberShop) => {
    let newItem: any;
    // Gallery uses direct upload logic now, handled by handleGalleryUpload
    if (section === 'services') {
      if (!newService.name.trim() || !newService.price.trim()) return;
      newItem = newService;
      const currentItems = editableShop[section] as any[];
      setEditableShop(prev => ({ ...prev, [section]: [...currentItems, newItem] }));
      setNewService({ name: '', price: '' });
    } else if (section === 'barbers') {
       // Barbers logic handles text fields, image is handled via state before adding
       if (!newBarber.name.trim() || !newBarber.specialty.trim() || !newBarber.imageUrl.trim()) {
           alert("Por favor completa nombre, especialidad y sube una foto.");
           return;
       }
       newItem = newBarber;
       const currentItems = editableShop[section] as any[];
       setEditableShop(prev => ({ ...prev, [section]: [...currentItems, newItem] }));
       setNewBarber({ name: '', specialty: '', imageUrl: '' });
    }
  };

  const handleRemoveItem = (section: keyof BarberShop, index: number) => {
    const newSection = (editableShop[section] as any[]).filter((_, i) => i !== index);
    setEditableShop(prev => ({ ...prev, [section]: newSection }));
  };

  const handleHourChange = (day: string, value: string) => {
    setEditableShop(prev => ({
        ...prev,
        hours: { ...prev.hours, [day]: value }
    }));
  };

  // --- Upload Logic ---

  const handleGalleryUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      setIsUploading(true);
      try {
          const url = await uploadShopImage(file, shop.id, 'gallery');
          setEditableShop(prev => ({ ...prev, gallery: [...prev.gallery, url] }));
          setUploadSuccess("¡Imagen subida a Storage correctamente!");
      } catch (error: any) {
          console.error("Upload failed", error);
          alert(error.message || "Error desconocido al subir imagen.");
      } finally {
          setIsUploading(false);
          // Reset input
          if (galleryInputRef.current) galleryInputRef.current.value = "";
      }
  };

  const handleNewBarberImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      setIsUploading(true);
      try {
          const url = await uploadShopImage(file, shop.id, 'barbers');
          setNewBarber(prev => ({ ...prev, imageUrl: url }));
          setUploadSuccess("Foto de barbero subida.");
      } catch (error: any) {
          console.error("Upload failed", error);
          alert(error.message || "Error desconocido al subir imagen.");
      } finally {
          setIsUploading(false);
          if (barberInputRef.current) barberInputRef.current.value = "";
      }
  };

  const handleEditBarberImageUpload = async (e: React.ChangeEvent<HTMLInputElement>, index: number) => {
      const file = e.target.files?.[0];
      if (!file) return;

      setIsUploading(true);
      try {
          const url = await uploadShopImage(file, shop.id, 'barbers');
          handleNestedChange<Barber>('barbers', index, 'imageUrl', url);
          setUploadSuccess("Foto actualizada.");
      } catch (error: any) {
           console.error("Upload failed", error);
           alert(error.message || "Error desconocido al subir imagen.");
      } finally {
          setIsUploading(false);
          if (editBarberInputRefs.current[index]) {
              editBarberInputRefs.current[index]!.value = "";
          }
      }
  };


  const handleSave = () => {
    onUpdateProfile(editableShop);
    setIsEditing(false);
  };

  const handleCancel = () => {
    setEditableShop(shop); // Revert changes
    setIsEditing(false);
  };

  return (
    <div className="w-full h-full bg-white overflow-y-auto p-6 lg:p-8 relative">
      {/* Success Toast */}
      {uploadSuccess && (
          <div className="fixed top-20 right-5 z-50 bg-green-600 text-white px-6 py-3 rounded-lg shadow-xl animate-fade-in flex items-center">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 mr-2" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
              </svg>
              {uploadSuccess}
          </div>
      )}

      <div className="max-w-7xl mx-auto">
        <header className="mb-10 text-center relative">
          {isEditing ? (
            <input type="text" name="name" value={editableShop.name} onChange={handleInputChange} className={`text-4xl lg:text-5xl font-extrabold tracking-tight text-center mb-2 ${inputClasses}`} />
          ) : (
            <h1 className="text-4xl lg:text-5xl font-extrabold text-gray-900 tracking-tight">{shop.name}</h1>
          )}
          {isEditing ? (
